import type { Lesson } from './types';

const LESSONS: Lesson[] = [
  { "id": 1, "module": "Fundamentos del Lenguaje", "title": "Variables con let", "theory": "Las variables son contenedores para almacenar datos. Con **`let`** declaras variables cuyo valor puede cambiar (reasignarse) a lo largo del programa.\n\n```js\n// Declaración e inicialización\nlet nombre = 'Ana';\nlet edad = 25;\n\n// Reasignación: la variable cambia de valor\nnombre = 'Luis';\nedad = 30;\n\n// Declarar sin inicializar da undefined\nlet ciudad;\nconsole.log(ciudad); // undefined\n```\n\n**Nomenclatura y buenas prácticas**:\n- Usa **camelCase**: `let nombreCompleto`, no `let nombrecompleto`\n- Usa nombres descriptivos: `let precioTotal` en vez de `let pt`\n- No uses palabras reservadas: `let`, `if`, `class`, `return`, etc.\n- No empieces con número ni uses guiones: `let 1nombre` o `let mi-var` son inválidos\n- Declara una variable por línea para mejor legibilidad\n- Inicializa siempre si conoces el valor inicial\n\n```js\n// Correcto\nlet nombreUsuario = 'Carlos';\nlet edadUsuario = 30;\n\n// Incorrecto (errores comunes)\n// let 2nombre = 'test';  // SyntaxError\n// let mi-var = 5;        // SyntaxError\n// let let = 'mal';       // SyntaxError\n```\n\n**Diferencia con `var`**: A diferencia de `var`, `let` tiene **ámbito de bloque** (`{}`) y no permite redeclarar la misma variable en el mismo ámbito. Es la forma moderna y recomendada de declarar variables mutables.", "exercise": "Declara `lenguaje` con valor 'JavaScript'. Declara `anio` con valor 1995. Declara `mensaje` que combine ambos con el operador `+` para producir el string: 'JavaScript fue creado en 1995'.", "solution": "let lenguaje = 'JavaScript';\nlet anio = 1995;\nlet mensaje = lenguaje + ' fue creado en ' + anio;", "tests": ["typeof lenguaje !== 'undefined'", "typeof anio !== 'undefined'", "typeof mensaje !== 'undefined'", "lenguaje === 'JavaScript'", "anio === 1995", "mensaje === 'JavaScript fue creado en 1995'"] },
  { "id": 2, "module": "Fundamentos del Lenguaje", "title": "Constantes", "theory": "Las constantes se declaran con **`const`** y no pueden reasignarse tras su inicialización. Son ideales para valores fijos o que no deben cambiar durante la ejecución.\n\n```js\nconst PI = 3.1416;\nconst GRAVEDAD = 9.81;\nconst PAIS = 'Colombia';\n\n// Esto lanza un TypeError:\n// PI = 3.14; // Assignment to constant variable\n\n// Las const deben inicializarse al declararse:\n// const valor;  // SyntaxError: Missing initializer in const declaration\n```\n\n**Nomenclatura**:\n- Para valores fijos conocidos (números mágicos, configuraciones) usa **SCREAMING_SNAKE_CASE**: `const COLOR_ROJO = '#FF0000'`, `const IVA = 0.21`\n- Para objetos o arrays que no se reasignarán pero cuyo contenido puede cambiar, usa camelCase: `const usuario = { nombre: 'Ana' }`\n\n```js\nconst IVA = 0.21;\nlet precio = 100;\nconst total = precio * (1 + IVA);\n```\n\n**Importante**: `const` evita la **reasignación de la variable**, pero si guarda un objeto o array, su **contenido sí puede modificarse**:\n\n```js\nconst persona = { nombre: 'Ana' };\npersona.nombre = 'Luis';  // ✓ permitido (mutación)\npersona.edad = 30;        // ✓ permitido (agregar propiedad)\n// persona = {};          // ✗ error (reasignación)\n\nconst numeros = [1, 2, 3];\nnumeros.push(4);          // ✓ permitido\nnumeros[0] = 10;          // ✓ permitido\n// numeros = [];          // ✗ error\n```\n\n**Buenas prácticas**:\n- Usa `const` por defecto. Solo usa `let` cuando sepas que la variable necesitará reasignarse.\n- Define valores mágicos (números, strings) como constantes con nombre: `const DESCUENTO_MAXIMO = 0.5` en vez de escribir `0.5` directamente en el código.", "exercise": "Declara `const IVA = 0.21`. Declara `let precioSinIva = 100`. Calcula `precioTotal` como `precioSinIva * (1 + IVA)`. Luego **reasigna** `precioSinIva` a 200 y calcula `precioTotal2` con la misma fórmula.", "solution": "const IVA = 0.21;\nlet precioSinIva = 100;\nlet precioTotal = precioSinIva * (1 + IVA);\nprecioSinIva = 200;\nlet precioTotal2 = precioSinIva * (1 + IVA);", "tests": ["IVA === 0.21", "precioTotal === 121", "precioTotal2 === 242"] },
  { "id": 3, "module": "Funciones", "title": "Funciones", "theory": "Las funciones son bloques de código reutilizable que realizan una tarea específica. Se declaran con la palabra clave **`function`**, pueden recibir **parámetros** y devolver un valor con **`return`**.\n\n```js\n// Declaración de función (Function Declaration)\nfunction saludar(nombre) {\n  return 'Hola, ' + nombre;\n}\n\n// Llamada o invocación\nlet mensaje = saludar('Ana');\nconsole.log(mensaje); // 'Hola, Ana'\n```\n\n**Partes de una función**:\n1. Palabra clave `function`\n2. Nombre en **camelCase** (verbo que describe la acción)\n3. Parámetros entre paréntesis (pueden ser 0 o más)\n4. Cuerpo entre llaves `{}` con el código a ejecutar\n5. `return` para devolver un resultado (opcional)\n\n```js\n// Función con varios parámetros\nfunction sumar(a, b) {\n  return a + b;\n}\n\n// Función sin return devuelve undefined\nfunction mostrar(mensaje) {\n  console.log(mensaje);\n  // No tiene return → undefined implícito\n}\n\n// Función sin parámetros\nfunction generarId() {\n  return Math.random().toString(36).substring(2);\n}\n```\n\n**Principios importantes**:\n- **Una función, una responsabilidad**: Cada función debe hacer una sola cosa bien\n- Usa nombres que describan la acción: `calcularTotal()`, `obtenerUsuario()`, `validarEmail()`\n- El `return` detiene la ejecución inmediatamente. Todo lo que esté después no se ejecuta\n- Si no usas `return`, la función devuelve `undefined`\n- Las funciones son **ciudadanos de primera clase**: pueden asignarse a variables, pasarse como argumento y retornarse desde otras funciones", "exercise": "Crea una función `esPar` que reciba un número y devuelva `true` si es par o `false` si es impar. Luego crea una función `filtrarPares` que reciba un array de números y retorne un nuevo array solo con los pares, usando `esPar`.", "solution": "function esPar(n) {\n  return n % 2 === 0;\n}\nfunction filtrarPares(numeros) {\n  return numeros.filter(esPar);\n}", "tests": ["typeof esPar === 'function'", "typeof filtrarPares === 'function'", { "type": "function", "code": "esPar(2)", "expected": true }, { "type": "function", "code": "esPar(3)", "expected": false }, { "type": "function", "code": "filtrarPares([1,2,3,4,5]).length", "expected": 2 }] },
  { "id": 4, "module": "Arrays y Objetos", "title": "Arrays", "theory": "Los **arrays** son listas ordenadas de valores. Se crean con corchetes `[]` y cada elemento se accede por su **índice** (empieza en 0).\n\n```js\nlet frutas = ['manzana', 'pera', 'uva'];\nconsole.log(frutas[0]); // 'manzana'\nconsole.log(frutas[2]); // 'uva'\nconsole.log(frutas.length); // 3\n```\n\nUn array puede mezclar tipos, aunque no es recomendable:\n```js\nlet mixto = [1, 'hola', true, null];\n```\n\n**Métodos básicos**:\n```js\nlet nums = [1, 2, 3];\nnums.push(4);       // añade al final → [1,2,3,4]\nnums.pop();         // saca del final → [1,2,3]\nnums.unshift(0);    // añade al inicio → [0,1,2,3]\nnums.shift();       // saca del inicio → [1,2,3]\n```\n\n**Recorrer arrays**:\n```js\nfor (let i = 0; i < frutas.length; i++) {\n  console.log(frutas[i]);\n}\n\nfor (let fruta of frutas) {\n  console.log(fruta);\n}\n```\n\n**Buenas prácticas**:\n- Usa arrays homogéneos (mismos tipos de datos)\n- `length` se actualiza automáticamente al añadir o quitar elementos\n- Puedes modificar elementos por índice: `nums[0] = 10`\n- Para clonar usa spread: `[...nums]`\n- Acceder a un índice inexistente devuelve `undefined`, no lanza error", "exercise": "Declara `let numeros = [10, 20, 30, 40, 50]`. Luego: agrega 60 al final con `push`, elimina el primer elemento con `shift`, y declara `suma` que contenga la suma de `numeros[0] + numeros[1] + numeros[2]`.", "solution": "let numeros = [10, 20, 30, 40, 50];\nnumeros.push(60);\nnumeros.shift();\nlet suma = numeros[0] + numeros[1] + numeros[2];", "tests": ["numeros.length === 4", "numeros[0] === 20", "numeros[3] === 60", "suma === 90"] },
  { "id": 5, "module": "Arrays y Objetos", "title": "Strings y template strings", "theory": "Los **strings** representan texto. Pueden definirse con comillas simples `''`, dobles `\"\"` o **template literals** (backticks `` ` ``).\n\n```js\nlet simple = 'Hola';\nlet doble = \"Mundo\";\nlet template = `Hola ${nombre}`; // Interpolación\n```\n\n**Template literals** permiten:\n1. **Interpolar variables**: `` `Hola ${nombre}` ``\n2. **Strings multilínea** sin \\n:\n```js\nlet texto = `Línea 1\nLínea 2\nLínea 3`;\n```\n3. **Expresiones**: `` `Total: ${precio * 1.21}` ``\n\n**Métodos útiles de string**:\n```js\n'hola'.toUpperCase();        // 'HOLA'\n'HOLA'.toLowerCase();        // 'hola'\n'  texto  '.trim();          // 'texto'\n'JavaScript'.includes('Script'); // true\n'abc'.repeat(3);             // 'abcabc'\n'a,b,c'.split(',');          // ['a','b','c']\n```\n\n**Buenas prácticas**:\n- Prefiere template literals sobre concatenación con `+`\n- Usa `toLowerCase()` para comparaciones sin importar mayúsculas\n- Los strings son **inmutables**: los métodos devuelven un nuevo string, no modifican el original\n- Para strings largos o con muchas variables, templates son más legibles", "exercise": "Declara `nombre = 'Carlos'`, `edad = 30`, `ciudad = 'Madrid'`. Declara `ficha` usando **template literal** que genere: 'Carlos (30) - Madrid'. Declara `mayusculas = ficha.toUpperCase()`.", "solution": "let nombre = 'Carlos';\nlet edad = 30;\nlet ciudad = 'Madrid';\nlet ficha = `${nombre} (${edad}) - ${ciudad}`;\nlet mayusculas = ficha.toUpperCase();", "tests": ["ficha === 'Carlos (30) - Madrid'", "mayusculas === 'CARLOS (30) - MADRID'"] },
  { "id": 6, "module": "Fundamentos del Lenguaje", "title": "Tipos de datos", "theory": "JavaScript tiene **tipado dinámico**: una variable puede cambiar de tipo en cualquier momento. No necesitas declarar el tipo explícitamente.\n\n```js\nlet dato = 25;      // number\ndato = 'Hola';      // ahora es string\ndato = true;        // ahora es boolean\n```\n\n**Tipos primitivos**:\n- **`number`**: enteros y decimales (`25`, `3.14`, `Infinity`, `NaN`)\n- **`string`**: texto entre comillas simples, dobles o backticks\n- **`boolean`**: `true` o `false`\n- **`null`**: valor vacío **intencionado** (lo asigna el programador)\n- **`undefined`**: variable declarada pero sin valor asignado\n\n```js\nlet entero = 42;\nlet decimal = 3.14;\nlet nombre = 'Carlos';\nlet esMayor = true;\nlet vacio = null;\nlet noDefinido;\n\nconsole.log(typeof noDefinido); // 'undefined'\nconsole.log(typeof vacio);      // 'object' (error histórico de JS)\nconsole.log(typeof 42);         // 'number'\nconsole.log(typeof 'Hola');     // 'string'\n```\n\n**NaN** (`Not a Number`) aparece al realizar operaciones matemáticas inválidas:\n```js\nconsole.log('texto' * 2);     // NaN\nconsole.log(typeof NaN);       // 'number' (sí, es de tipo number)\nconsole.log(NaN === NaN);      // false (NaN no es igual a sí mismo)\nconsole.log(isNaN('texto'));   // true\n```\n\n**Buenas prácticas**:\n- Usa **`===`** (comparación estricta) en lugar de `==` para evitar coerción automática de tipos\n- No confundas `null` (asignado a propósito por el programador) con `undefined` (JS lo asigna cuando no hay valor)\n- Usa `typeof` para depurar y verificar tipos en tiempo de ejecución", "exercise": "Declara `producto = 'Laptop'`, `precio = 999.99`, `disponible = true`, `stock = null`. Declara `descuento` sin inicializar. Declara `tipoDescuento` que almacene el resultado de aplicar `typeof descuento`.", "solution": "let producto = 'Laptop';\nlet precio = 999.99;\nlet disponible = true;\nlet stock = null;\nlet descuento;\nlet tipoDescuento = typeof descuento;", "tests": ["typeof producto === 'string'", "typeof precio === 'number'", "typeof disponible === 'boolean'", "stock === null", "tipoDescuento === 'undefined'"] },
  { "id": 7, "module": "Fundamentos del Lenguaje", "title": "Operadores", "theory": "Los **operadores aritméticos** realizan cálculos matemáticos con números.\n\n```js\nlet suma = 10 + 3;          // 13 | adición\nlet resta = 10 - 3;         // 7  | sustracción\nlet mult = 10 * 3;          // 30 | multiplicación\nlet div = 10 / 3;           // 3.333... | división\nlet modulo = 10 % 3;        // 1  | resto (módulo)\nlet expo = 10 ** 3;         // 1000 | exponenciación (ES2016)\n```\n\n**Operadores de incremento/decremento**:\n```js\nlet contador = 0;\ncontador++;   // post-incremento (primero usa, luego incrementa)\n++contador;   // pre-incremento (primero incrementa, luego usa)\ncontador--;   // decremento\n```\n\n**Operadores de asignación combinada**:\n```js\nlet x = 10;\nx += 5;   // x = x + 5 → 15\nx -= 3;   // x = x - 3 → 12\nx *= 2;   // x = x * 2 → 24\nx /= 4;   // x = x / 4 → 6\nx %= 4;   // x = x % 4 → 2\nx **= 2;  // x = x ** 2 → 4\n```\n\n**Precedencia de operadores** (como en matemáticas):\n1. Paréntesis: `( )`\n2. Exponenciación: `**`\n3. Multiplicación, división, módulo: `*`, `/`, `%`\n4. Suma y resta: `+`, `-`\n\n```js\nlet resultado = 10 + 3 * 2;    // 16 (multiplica primero)\nlet correcto = (10 + 3) * 2;   // 26 (paréntesis primero)\n```\n\n**Buenas prácticas**: Usa paréntesis para hacer explícita la precedencia, aunque no sea necesaria. Esto mejora la legibilidad del código.", "exercise": "Declara `x = 20`, `y = 7`. Calcula: `cociente` usando `Math.floor(x / y)` (división entera), `residuo` como `x % y`, `elevado` como `x ** y`. Luego usa operador combinado `+= 10` sobre `x` (reasigna la misma variable `x`).", "solution": "let x = 20;\nlet y = 7;\nlet cociente = Math.floor(x / y);\nlet residuo = x % y;\nlet elevado = x ** y;\nx += 10;", "tests": ["x === 30", "cociente === 2", "residuo === 6", "elevado === 1280000000"] },
  { "id": 8, "module": "Fundamentos del Lenguaje", "title": "Entrada/salida básica", "theory": "La **comunicación** entre el programa y el usuario se maneja con funciones de entrada y salida.\n\n**Salida por consola** (para depuración y desarrollo):\n```js\nconsole.log('Mensaje');          // mensaje simple\nconsole.log('Valor:', 42);       // múltiples argumentos\nconsole.warn('Cuidado...');      // advertencia en amarillo\nconsole.error('Error...');        // error en rojo\nconsole.table([1, 2, 3]);        // muestra como tabla\nconsole.group('Grupo');           // agrupa mensajes\nconsole.time('t');                // cronómetro\n```\n\n**Interacción con el usuario** (en navegador):\n```js\nalert('¡Bienvenido!');                  // mensaje emergente modal\nlet dato = prompt('¿Cómo te llamas?');  // entrada de texto (devuelve string)\nlet numero = Number(prompt('Edad:'));   // convertir string a número\nlet confirmar = confirm('¿Seguro?');    // true o false\n```\n\n**Template literals** (backticks `` ` ``) permiten **interpolar variables** de forma legible:\n```js\nlet nombre = 'Ana';\nlet edad = 30;\n\n// Con template literals (recomendado):\nconsole.log(`Hola, soy ${nombre} y tengo ${edad} años.`);\n\n// Equivalente con concatenación (menos legible):\nconsole.log('Hola, soy ' + nombre + ' y tengo ' + edad + ' años.');\n```\n\n**Buenas prácticas**:\n- Usa **template literals** en lugar de concatenación con `+` (más limpio y legible)\n- No abuses de `alert()` o `prompt()` en producción (bloquean la ejecución)\n- Usa `console.log()` para depuración, pero elimínalos del código final o usa un sistema de logging", "exercise": "Declara `nombre = 'Marta'`, `edad = 28`, `ciudad = 'Barcelona'`. Declara `presentacion` usando un **template literal** (backticks `` ` ``) que genere exactamente: 'Soy Marta, tengo 28 años y vivo en Barcelona'.", "solution": "let nombre = 'Marta';\nlet edad = 28;\nlet ciudad = 'Barcelona';\nlet presentacion = `Soy ${nombre}, tengo ${edad} años y vivo en ${ciudad}`;", "tests": ["presentacion === 'Soy Marta, tengo 28 años y vivo en Barcelona'"] },
  { "id": 9, "module": "Fundamentos del Lenguaje", "title": "Conversión de tipos", "theory": "En JavaScript puedes convertir entre tipos de forma **explícita** usando funciones constructoras. Esto es importante porque muchas operaciones requieren un tipo específico.\n\n```js\n// String → Number\nNumber('42');        // 42\nNumber('3.14');      // 3.14\nNumber('');          // 0\nNumber('   ');       // 0\nNumber('hola');      // NaN\n\nparseInt('42.7');    // 42 (entero, trunca decimales)\nparseInt('101', 2);  // 5 (binario a decimal)\nparseFloat('3.14');  // 3.14\n\n// Number → String\nString(100);         // '100'\n(100).toString();    // '100'\n(3.14).toFixed(1);   // '3.1' (formatea decimales)\n\n// A boolean (truthy/falsy)\nBoolean(1);           // true\nBoolean(0);           // false\nBoolean('');          // false\nBoolean('false');     // true (string no vacío, ¡cuidado!)\nBoolean(null);        // false\nBoolean(undefined);   // false\nBoolean(NaN);         // false\n```\n\n**Valores truthy y falsy**:\n| Falsy | Truthy |\n|-------|--------|\n| `false` | `true` |\n| `0`, `-0` | cualquier número ≠ 0 |\n| `''` (string vacío) | cualquier string no vacío |\n| `null` | objetos, arrays (incluso vacíos) |\n| `undefined` | |\n| `NaN` | |\n\n**Buenas prácticas**: Haz conversión explícita siempre. No confíes en la coerción automática de JavaScript, ya que puede dar resultados inesperados.", "exercise": "Declara `entrada = '25.8'`. Conviértela a: `numero` (número decimal con `Number()`), `entero` (entero con `parseInt()`), `texto` (string desde `numero` con `String()`), `esTruthy` (booleano con `Boolean(entrada)`).", "solution": "let entrada = '25.8';\nlet numero = Number(entrada);\nlet entero = parseInt(entrada);\nlet texto = String(numero);\nlet esTruthy = Boolean(entrada);", "tests": ["numero === 25.8", "entero === 25", "texto === '25.8'", "esTruthy === true"] },
  { "id": 10, "module": "Fundamentos del Lenguaje", "title": "Mini-calculadora", "theory": "Combina **variables**, **operadores aritméticos** y funciones del objeto **`Math`** para realizar cálculos complejos.\n\n```js\nlet a = 15, b = 4;\nlet suma = a + b;           // 19\nlet resta = a - b;          // 11\nlet producto = a * b;       // 60\nlet cociente = a / b;       // 3.75\nlet resto = a % b;          // 3\n```\n\n**El objeto `Math`** ofrece operaciones matemáticas avanzadas:\n```js\nMath.floor(3.7);     // 3 (redondeo hacia abajo)\nMath.ceil(3.2);      // 4 (redondeo hacia arriba)\nMath.round(3.5);     // 4 (redondeo estándar)\nMath.sqrt(25);       // 5 (raíz cuadrada)\nMath.max(1, 5, 3);   // 5 (valor máximo)\nMath.min(1, 5, 3);   // 1 (valor mínimo)\nMath.abs(-5);        // 5 (valor absoluto)\nMath.random();       // número aleatorio entre 0 (incluido) y 1 (excluido)\n```\n\n**Formateo de decimales** con `toFixed()`:\n```js\nlet precio = 19.999;\nconsole.log(precio.toFixed(2));      // '20.00' (devuelve string)\nconsole.log(Number(precio.toFixed(2))); // 20 (convertido a número)\n```\n\n**Números aleatorios en un rango**:\n```js\n// Aleatorio entre min y max (incluidos)\nfunction aleatorio(min, max) {\n  return Math.floor(Math.random() * (max - min + 1)) + min;\n}\nconsole.log(aleatorio(1, 10));  // número del 1 al 10\n```\n\n**Buenas prácticas**:\n- Nombra las variables según su propósito (`total`, `precioFinal`, `descuento`)\n- Redondea los resultados financieros con `toFixed()` o `Math.round()`\n- Separa la lógica en pasos claros y declarativos", "exercise": "Declara `a = 17`, `b = 5`. Calcula: `suma`, `resta`, `producto`, `division`, `media` ((a + b) / 2), `resto` (a % b) y `maximo` (el valor más grande entre a y b usando `Math.max`).", "solution": "let a = 17;\nlet b = 5;\nlet suma = a + b;\nlet resta = a - b;\nlet producto = a * b;\nlet division = a / b;\nlet media = (a + b) / 2;\nlet resto = a % b;\nlet maximo = Math.max(a, b);", "tests": ["suma === 22", "resta === 12", "producto === 85", "resto === 2", "media === 11", "maximo === 17"] },
  { "id": 11, "module": "Control de Flujo", "title": "Condicionales if/else", "theory": "Las estructuras **`if`/`else`** permiten ejecutar código según condiciones booleanas. Son la base de la toma de decisiones en programación.\n\n```js\nlet edad = 18;\n\nif (edad >= 18) {\n  console.log('Eres mayor de edad');\n} else {\n  console.log('Eres menor de edad');\n}\n```\n\n**Variantes**:\n```js\n// if con else if\nlet nota = 85;\nif (nota >= 90) {\n  console.log('Sobresaliente');\n} else if (nota >= 70) {\n  console.log('Notable');\n} else if (nota >= 50) {\n  console.log('Aprobado');\n} else {\n  console.log('Reprobado');\n}\n\n// if sin llaves (solo para una línea)\nif (edad >= 18) console.log('Mayor');\n```\n\n**Operador ternario** (`condición ? valorSiTrue : valorSiFalse`):\n```js\nlet mensaje = edad >= 18 ? 'Mayor' : 'Menor';\n// Es equivalente a:\nlet mensaje2;\nif (edad >= 18) {\n  mensaje2 = 'Mayor';\n} else {\n  mensaje2 = 'Menor';\n}\n```\n\n**Errores comunes**:\n- Usar `=` (asignación) en lugar de `===` (comparación)\n- Olvidar `else` cuando necesitas ambos caminos\n- Condiciones muy complejas (mejor dividir en variables auxiliares)\n- No considerar el caso `else` (valores inesperados)", "exercise": "Declara `numero = 15`. Usando condicionales, asigna a `categoria`: 'pequeño' si es menor que 10, 'mediano' si está entre 10 y 50 inclusive, o 'grande' si es mayor que 50.", "solution": "let numero = 15;\nlet categoria;\nif (numero < 10) {\n  categoria = 'pequeño';\n} else if (numero <= 50) {\n  categoria = 'mediano';\n} else {\n  categoria = 'grande';\n}", "tests": ["numero === 15", "categoria === 'mediano'"] },
  { "id": 12, "module": "Control de Flujo", "title": "Operadores lógicos", "theory": "Los **operadores lógicos** combinan condiciones booleanas: **`&&`** (AND, ambas deben ser true), **`||`** (OR, al menos una debe ser true), **`!`** (NOT, invierte el booleano).\n\n```js\nlet edad = 25;\nlet tieneCarnet = true;\n\n// AND: ambas condiciones deben cumplirse\nlet puedeConducir = edad >= 18 && tieneCarnet;\nconsole.log(puedeConducir); // true\n\n// OR: al menos una condición se cumple\nlet esFinDeSemana = false;\nlet esFeriado = true;\nlet descansa = esFinDeSemana || esFeriado;\nconsole.log(descansa); // true\n\n// NOT: invierte el valor\nlet activo = false;\nconsole.log(!activo); // true\n```\n\n**Short-circuit evaluation** (evaluación en cortocircuito):\n```js\n// && devuelve el primer falsy o el último truthy\nconsole.log(0 && 'Hola');    // 0\nconsole.log(1 && 'Hola');    // 'Hola'\n\n// || devuelve el primer truthy o el último falsy\nconsole.log('' || 'default'); // 'default'\nconsole.log(0 || null);       // null\n\n// Uso común: valor por defecto\nlet nombre = usuario.nombre || 'Invitado';\n```\n\n**Buenas prácticas**:\n- Agrupa condiciones complejas con paréntesis: `(a > 0 && b > 0) || (c > 0)`\n- No abuses del short-circuit; a veces un `if` es más legible\n- Recuerda: `!` tiene alta precedencia, usa paréntesis si combinas con `&&` o `||`", "exercise": "Declara `edad = 20`, `tienePermiso = false`. Declara `puedeEntrar` que sea true solo si (edad >= 18 **Y** tienePermiso) **O** (edad >= 21).", "solution": "let edad = 20;\nlet tienePermiso = false;\nlet puedeEntrar = (edad >= 18 && tienePermiso) || (edad >= 21);", "tests": ["edad === 20", "tienePermiso === false", "puedeEntrar === false"] },
  { "id": 13, "module": "Control de Flujo", "title": "Bucles for", "theory": "El bucle **`for`** repite código un número determinado de veces. Tiene tres partes: **inicialización**, **condición** y **actualización**.\n\n```js\nfor (let i = 1; i <= 5; i++) {\n  console.log(i); // 1, 2, 3, 4, 5\n}\n```\n\n**Partes del bucle**:\n1. `let i = 1` — inicialización (se ejecuta una vez al inicio)\n2. `i <= 5` — condición (se evalúa antes de cada iteración)\n3. `i++` — actualización (se ejecuta al final de cada iteración)\n\n**Variantes**:\n```js\n// Recorrer array por índice\nlet colores = ['rojo', 'verde', 'azul'];\nfor (let i = 0; i < colores.length; i++) {\n  console.log(colores[i]);\n}\n\n// Decremento\nfor (let i = 10; i >= 0; i--) {\n  console.log(i); // 10, 9, ..., 0\n}\n\n// Paso de 2 en 2\nfor (let i = 0; i <= 10; i += 2) {\n  console.log(i); // 0, 2, 4, 6, 8, 10\n}\n\n// Bucle anidado (tabla de multiplicar)\nfor (let i = 1; i <= 3; i++) {\n  for (let j = 1; j <= 3; j++) {\n    console.log(`${i} x ${j} = ${i * j}`);\n  }\n}\n```\n\n**Errores comunes**:\n- Bucle infinito: `for (let i = 0; i < 10; i--)` (nunca llega a 10)\n- Off-by-one: usar `<` en vez de `<=` o viceversa\n- Olvidar `let` en la inicialización (contamina el ámbito global)\n- Modificar el array mientras lo recorres", "exercise": "Declara un array vacío `pares`. Usa un bucle `for` que itere del 1 al 20 y guarde solo los números pares en el array.", "solution": "let pares = [];\nfor (let i = 1; i <= 20; i++) {\n  if (i % 2 === 0) {\n    pares.push(i);\n  }\n}", "tests": ["pares.length === 10", "pares[0] === 2", "pares[pares.length - 1] === 20"] },
  { "id": 14, "module": "Control de Flujo", "title": "Bucles while", "theory": "El bucle **`while`** ejecuta código mientras una condición sea `true`. Útil cuando no sabes de antemano cuántas iteraciones se necesitan.\n\n```js\nlet i = 1;\nwhile (i <= 5) {\n  console.log(i);\n  i++;\n}\n```\n\n**`do...while`** (ejecuta al menos una vez):\n```js\nlet j = 0;\ndo {\n  console.log(j); // Se ejecuta al menos una vez\n  j++;\n} while (j < 0);\n```\n\n**¿Cuándo usar `while` vs `for`?**\n- `for`: cuando sabes el número exacto de iteraciones (recorrer array, contar)\n- `while`: cuando la condición depende de algo que cambia dentro del bucle (leer datos hasta condición, esperar un estado)\n\n```js\n// Leer datos hasta encontrar 'stop'\nlet datos = ['a', 'b', 'c', 'stop', 'd'];\nlet idx = 0;\nwhile (datos[idx] !== 'stop') {\n  console.log(datos[idx]);\n  idx++;\n}\n```\n\n**Errores comunes**:\n- Olvidar actualizar la variable de control → **bucle infinito**\n- Condición que nunca se cumple → el bucle no se ejecuta (salvo `do...while`)\n- No inicializar la variable antes del bucle", "exercise": "Declara `contador = 10`. Usa un bucle `while` para contar hacia atrás: declara un array vacío `cuentaAtras` y, mientras `contador >= 0`, agregalo al array y decrementalo.", "solution": "let contador = 10;\nlet cuentaAtras = [];\nwhile (contador >= 0) {\n  cuentaAtras.push(contador);\n  contador--;\n}", "tests": ["cuentaAtras.length === 11", "cuentaAtras[0] === 10", "cuentaAtras[10] === 0"] },
  { "id": 15, "module": "Control de Flujo", "title": "Manejo de errores", "theory": "**`try...catch`** captura errores en tiempo de ejecución sin que el programa se rompa. El bloque `try` contiene código que podría fallar, y `catch` maneja el error.\n\n```js\ntry {\n  let resultado = JSON.parse('{invalido}');\n} catch (error) {\n  console.log('Error capturado:', error.message);\n}\n\n// El programa sigue ejecutándose\nconsole.log('Esto sí se ejecuta');\n```\n\n**Estructura completa**:\n```js\ntry {\n  // Código que puede lanzar un error\n  let data = JSON.parse(jsonString);\n  console.log('Éxito:', data);\n} catch (error) {\n  // Manejo del error\n  console.error('Error al parsear JSON:', error.message);\n} finally {\n  // Siempre se ejecuta, haya error o no\n  console.log('Bloque finally: limpieza aquí');\n}\n```\n\n**Lanzar errores con `throw`**:\n```js\nfunction dividir(a, b) {\n  if (b === 0) {\n    throw new Error('No se puede dividir por cero');\n  }\n  return a / b;\n}\n\ntry {\n  console.log(dividir(10, 0));\n} catch (e) {\n  console.log(e.message); // 'No se puede dividir por cero'\n}\n```\n\n**Tipos de error en JS**:\n- `Error` — genérico\n- `SyntaxError` — error de sintaxis\n- `TypeError` — tipo incorrecto\n- `ReferenceError` — variable no existe\n- `RangeError` — valor fuera de rango\n\n**Buenas prácticas**:\n- Captura errores específicos: no uses `catch` genérico sin manejar el error\n- El `finally` es ideal para liberar recursos (cerrar conexiones, limpiar)\n- No abuses de try/catch para control de flujo normal", "exercise": "Declara `resultado = 'ok'`. Usa `try/catch` para ejecutar `JSON.parse('{invalido}')`. Si hay error, asigna `'error'` a `resultado`. Además, declara `hayError = true` solo dentro del `catch`.", "solution": "let resultado = 'ok';\nlet hayError = false;\ntry {\n  JSON.parse('{invalido}');\n} catch (e) {\n  resultado = 'error';\n  hayError = true;\n}", "tests": ["resultado === 'error'", "hayError === true"] },
  { "id": 16, "module": "Funciones", "title": "Parámetros y retorno", "theory": "Los **parámetros** son valores que recibe una función para trabajar con ellos. El **`return`** devuelve un valor al punto donde se llamó la función.\n\n```js\nfunction sumar(a, b) {\n  return a + b;\n}\n\nlet resultado = sumar(5, 3);\nconsole.log(resultado); // 8\n```\n\n**Parámetros por defecto** (ES6):\n```js\nfunction saludar(nombre = 'Invitado') {\n  return 'Hola, ' + nombre;\n}\n\nconsole.log(saludar('Ana')); // 'Hola, Ana'\nconsole.log(saludar());      // 'Hola, Invitado'\n```\n\n**Múltiples parámetros y orden**:\n```js\nfunction crearProducto(nombre, precio, stock = 0) {\n  return { nombre, precio, stock };\n}\n\nconsole.log(crearProducto('Laptop', 1200, 10));\n```\n\n**Return temprano** (early return) para simplificar:\n```js\nfunction validarEdad(edad) {\n  if (edad < 0) return 'Edad inválida';\n  if (edad < 18) return 'Menor de edad';\n  return 'Mayor de edad';\n}\n```\n\n**Funciones sin return**: devuelven `undefined` implícitamente.\n\n**Buenas prácticas**:\n- Limita el número de parámetros (ideal ≤ 3). Si necesitas más, usa un objeto\n- Usa parámetros por defecto en vez de validar con `if`\n- Una función debe hacer una sola cosa y tener un solo propósito", "exercise": "Crea una función `calcularPrecio` que reciba `precioBase` (Number) y opcionalmente `descuento` (Number, default 0) e `impuesto` (Number, default 0.21). Debe retornar el precio final: (precioBase - descuento) * (1 + impuesto). Si precioBase es negativo, retorna 0.", "solution": "function calcularPrecio(precioBase, descuento = 0, impuesto = 0.21) {\n  if (precioBase < 0) return 0;\n  return (precioBase - descuento) * (1 + impuesto);\n}", "tests": ["typeof calcularPrecio === 'function'", { "type": "function", "code": "calcularPrecio(100)", "expected": 121 }, { "type": "function", "code": "calcularPrecio(100, 20)", "expected": 96.8 }, { "type": "function", "code": "calcularPrecio(100, 20, 0.1)", "expected": 88 }, { "type": "function", "code": "calcularPrecio(-10)", "expected": 0 }] },
  { "id": 17, "module": "Funciones", "title": "Funciones flecha", "theory": "Las **arrow functions** (`=>`) son una sintaxis más concisa para escribir funciones. No tienen su propio `this` ni `arguments`.\n\n```js\n// Función tradicional\nfunction sumar(a, b) { return a + b; }\n\n// Arrow function (varias formas)\nconst sumar = (a, b) => { return a + b; };\nconst sumar = (a, b) => a + b;   // return implícito (sin llaves)\nconst cuadrado = n => n * n;     // un parámetro: sin paréntesis\nconst aleatorio = () => Math.random(); // sin parámetros\n```\n\n**Return implícito**: si el cuerpo solo tiene una expresión, puedes omitir `return` y las llaves:\n```js\nconst doble = n => n * 2;\n\n// Para objetos, envuélvelos en paréntesis:\nconst crearPersona = (nombre, edad) => ({ nombre, edad });\n```\n\n**Diferencias clave con function tradicional**:\n- No tienen `this` propio (heredan del ámbito padre)\n- No tienen objeto `arguments`\n- No pueden usarse como constructores (con `new`)\n- No tienen propiedad `prototype`\n\n```js\n// this en arrow vs tradicional\nconst obj = {\n  nombre: 'Ana',\n  saludarTradicional: function() { return 'Hola ' + this.nombre; },\n  saludarArrow: () => 'Hola ' + this.nombre  // this no es el objeto\n};\n```\n\n**Buenas prácticas**:\n- Usa arrow functions para callbacks cortos (`map`, `filter`, `reduce`, `forEach`)\n- Usa function tradicional para métodos de objetos que necesiten su propio `this`\n- El return implícito mejora la legibilidad en funciones simples", "exercise": "Crea una arrow function `obtenerMayores` que reciba un array de números y retorne los mayores a 10. Crea otra arrow function `sumarArray` que sume todos los elementos de un array usando reduce.", "solution": "const obtenerMayores = arr => arr.filter(n => n > 10);\nconst sumarArray = arr => arr.reduce((acc, n) => acc + n, 0);", "tests": ["typeof obtenerMayores === 'function'", "typeof sumarArray === 'function'", { "type": "function", "code": "obtenerMayores([5, 15, 8, 20]).length", "expected": 2 }, { "type": "function", "code": "sumarArray([1, 2, 3, 4, 5])", "expected": 15 }] },
  { "id": 18, "module": "Funciones", "title": "Scope de variables", "theory": "El **scope** (ámbito) determina dónde es accesible una variable. JavaScript tiene **scope global**, **scope de función** y **scope de bloque** (con `let`/`const`).\n\n```js\n// Scope global\nlet global = 'accesible desde cualquier parte';\n\nfunction miFuncion() {\n  // Scope de función\n  let localFuncion = 'solo dentro de la función';\n  console.log(global);     // ✓ accesible\n  console.log(localFuncion); // ✓ accesible\n}\n\nconsole.log(localFuncion); // ✗ ReferenceError\n```\n\n**Scope de bloque** (`{}`):\n```js\nif (true) {\n  let x = 10;\n  const y = 20;\n  var z = 30;  // var ignora el scope de bloque\n}\n\nconsole.log(x); // ReferenceError: x no está definida\nconsole.log(y); // ReferenceError: y no está definida\nconsole.log(z); // 30 (var se filtra fuera del bloque)\n```\n\n**Shadowing** (sombreado): una variable local oculta a la global con el mismo nombre:\n```js\nlet nombre = 'Global';\n\nfunction mostrar() {\n  let nombre = 'Local';\n  console.log(nombre); // 'Local'\n}\n```\n\n**Temporal Dead Zone (TDZ)**: con `let` y `const`, no puedes acceder a la variable antes de su declaración:\n```js\nconsole.log(x); // ReferenceError (TDZ)\nlet x = 5;\n```\n\n**Buenas prácticas**:\n- Prefiere `const` por defecto, `let` cuando necesites reasignar\n- Evita variables globales (contaminación del ámbito global)\n- Usa nombres diferentes para evitar shadowing confuso\n- Declara las variables al inicio del bloque para evitar TDZ", "exercise": "Declara `x = 10` (global). Crea una función `calcular` que declare `x = 20` (local) y retorne `x * 2`. Luego declara `resultadoLocal` que almacene el retorno de `calcular()`. Declara `resultadoGlobal` como `x * 2` usando la x global.", "solution": "let x = 10;\nfunction calcular() {\n  let x = 20;\n  return x * 2;\n}\nlet resultadoLocal = calcular();\nlet resultadoGlobal = x * 2;", "tests": ["x === 10", "resultadoLocal === 40", "resultadoGlobal === 20"] },
  { "id": 19, "module": "Funciones", "title": "Refactorización con funciones", "theory": "**Refactorizar** es reescribir código existente para mejorarlo sin cambiar su comportamiento. Extraer funciones es una de las técnicas más poderosas.\n\n**Antes** (código repetido):\n```js\nlet numeros1 = [1, 2, 3, 4, 5];\nlet suma1 = 0;\nfor (let n of numeros1) suma1 += n;\nconsole.log(suma1);\n\nlet numeros2 = [10, 20, 30];\nlet suma2 = 0;\nfor (let n of numeros2) suma2 += n;\nconsole.log(suma2);\n```\n\n**Después** (refactorizado con función):\n```js\nfunction sumarArray(arr) {\n  return arr.reduce((acc, n) => acc + n, 0);\n}\n\nconsole.log(sumarArray([1, 2, 3, 4, 5]));\nconsole.log(sumarArray([10, 20, 30]));\n```\n\n**Principios SOLID (adaptados)**:\n- **Responsabilidad única**: cada función hace una cosa\n- **DRY** (Don't Repeat Yourself): no repitas código, extráelo a una función\n- **Nombres descriptivos**: el nombre debe explicar qué hace\n\n```js\n// Mal\nfunction proc(d) { return d * 0.21 + d; }\n\n// Bien\nfunction calcularTotalConIVA(precio) {\n  return precio * 1.21;\n}\n```\n\n**Beneficios de refactorizar**:\n- Código más legible y mantenible\n- Menos errores (se corrige en un solo lugar)\n- Reutilización\n- Más fácil de testear", "exercise": "Dado el siguiente código sin refactorizar, créalo exactamente igual y luego declara la función `esPar` que unifique la lógica: `let nums1 = [1, 2, 3, 4, 5]; let pares1 = []; for (let n of nums1) { if (n % 2 === 0) pares1.push(n); } let nums2 = [10, 15, 20, 25]; let pares2 = []; for (let n of nums2) { if (n % 2 === 0) pares2.push(n); }` Luego declara `pares1Refactor` y `pares2Refactor` usando `esPar`.", "solution": "function esPar(n) { return n % 2 === 0; }\nlet nums1 = [1, 2, 3, 4, 5];\nlet pares1 = [];\nfor (let n of nums1) { if (n % 2 === 0) pares1.push(n); }\nlet nums2 = [10, 15, 20, 25];\nlet pares2 = [];\nfor (let n of nums2) { if (n % 2 === 0) pares2.push(n); }\nlet pares1Refactor = nums1.filter(esPar);\nlet pares2Refactor = nums2.filter(esPar);", "tests": ["typeof esPar === 'function'", "pares1Refactor.length === 2", "pares2Refactor.length === 2", "JSON.stringify(pares1Refactor) === '[2,4]'", "JSON.stringify(pares2Refactor) === '[10,20]'"] },
  { "id": 20, "module": "Arrays y Objetos", "title": "Métodos map y filter", "theory": "**`map()`** transforma cada elemento de un array y devuelve un nuevo array del mismo tamaño. **`filter()`** selecciona elementos que cumplan una condición y devuelve un nuevo array.\n\n```js\nconst numeros = [1, 2, 3, 4, 5];\n\n// map: transforma cada elemento\nconst dobles = numeros.map(n => n * 2);\nconsole.log(dobles); // [2, 4, 6, 8, 10]\n\n// filter: selecciona elementos\nconst pares = numeros.filter(n => n % 2 === 0);\nconsole.log(pares); // [2, 4]\n```\n\n**Ambos son inmutables** (no modifican el array original):\n```js\nconst original = ['a', 'b', 'c'];\nconst mayusculas = original.map(letra => letra.toUpperCase());\nconsole.log(original);    // ['a', 'b', 'c'] (sin cambios)\nconsole.log(mayusculas);  // ['A', 'B', 'C']\n```\n\n**Chaining (encadenamiento)**:\n```js\nconst nums = [1, 2, 3, 4, 5, 6];\nconst resultado = nums\n  .filter(n => n % 2 === 0)    // [2, 4, 6]\n  .map(n => n * 10);           // [20, 40, 60]\n```\n\n**Usos comunes**:\n```js\n// Extraer propiedades de objetos\nconst usuarios = [{ nombre: 'Ana', edad: 25 }, { nombre: 'Luis', edad: 30 }];\nconst nombres = usuarios.map(u => u.nombre); // ['Ana', 'Luis']\nconst mayores = usuarios.filter(u => u.edad >= 30);\n\n// Formatear datos\nconst precios = [100, 200, 300];\nconst conIVA = precios.map(p => p * 1.21); // [121, 242, 363]\n```\n\n**Buenas prácticas**:\n- Prefiere `map`/`filter` sobre bucles `for` para transformaciones\n- Encadena operaciones para legibilidad, pero evita cadenas muy largas\n- Dentro de `map`, evita efectos secundarios (no modifiques objetos externos)", "exercise": "Dado `let personas = [{nombre:'Ana', edad:17}, {nombre:'Luis', edad:22}, {nombre:'Carlos', edad:15}, {nombre:'Marta', edad:30}]`. Usa `filter` para obtener los mayores de edad y `map` para obtener un array solo con sus nombres. Guarda en `mayores`.", "solution": "let personas = [{nombre:'Ana', edad:17}, {nombre:'Luis', edad:22}, {nombre:'Carlos', edad:15}, {nombre:'Marta', edad:30}];\nlet mayores = personas.filter(p => p.edad >= 18).map(p => p.nombre);", "tests": ["mayores.length === 2", "mayores[0] === 'Luis'", "mayores[1] === 'Marta'"] },
  { "id": 21, "module": "Arrays y Objetos", "title": "Método reduce", "theory": "**`reduce()`** recorre el array acumulando un valor. Es muy versátil: puede sumar, multiplicar, agrupar, aplanar, etc.\n\n```js\nconst numeros = [1, 2, 3, 4, 5];\n\nconst suma = numeros.reduce((acumulador, actual) => acumulador + actual, 0);\nconsole.log(suma); // 15\n```\n\n**Parámetros**:\n1. `acumulador` — valor acumulado de iteraciones anteriores\n2. `actual` — elemento actual del array\n3. `indice` (opcional) — índice del elemento\n4. `array` (opcional) — array original\n5. **Valor inicial** (segundo argumento de `reduce`) — 0 en el ejemplo\n\n**Ejemplos avanzados**:\n```js\n// Máximo valor\nconst max = [3, 7, 2, 9, 5].reduce((max, n) => n > max ? n : max, -Infinity);\n\n// Contar ocurrencias\nconst frutas = ['manzana', 'pera', 'manzana', 'uva', 'pera', 'manzana'];\nconst conteo = frutas.reduce((acc, fruta) => {\n  acc[fruta] = (acc[fruta] || 0) + 1;\n  return acc;\n}, {});\n// { manzana: 3, pera: 2, uva: 1 }\n\n// Aplanar array de arrays\nconst arrays = [[1, 2], [3, 4], [5, 6]];\nconst plano = arrays.reduce((acc, arr) => acc.concat(arr), []);\n// [1, 2, 3, 4, 5, 6]\n```\n\n**¿Cuándo usar reduce?**\n- Sumar o promediar valores numéricos\n- Agrupar objetos por una propiedad\n- Convertir array en objeto\n- Calcular valores complejos (máximo, mínimo, producto)\n\n**Buenas prácticas**:\n- Siempre proporciona un valor inicial para evitar errores con arrays vacíos\n- Si la lógica es compleja, extrae el callback a una función con nombre\n- Para sumas simples, `reduce` es mejor que un bucle `for`", "exercise": "Dado `let ventas = [{producto:'A', monto:100}, {producto:'B', monto:200}, {producto:'A', monto:150}, {producto:'C', monto:300}]`. Usa `reduce` para obtener un objeto `totales` donde cada clave sea el producto y el valor sea la suma de montos.", "solution": "let ventas = [{producto:'A', monto:100}, {producto:'B', monto:200}, {producto:'A', monto:150}, {producto:'C', monto:300}];\nlet totales = ventas.reduce((acc, v) => {\n  acc[v.producto] = (acc[v.producto] || 0) + v.monto;\n  return acc;\n}, {});", "tests": ["totales.A === 250", "totales.B === 200", "totales.C === 300"] },
  { "id": 22, "module": "Arrays y Objetos", "title": "Objetos literales", "theory": "Los **objetos** agrupan datos relacionados en pares **clave: valor**. Las claves son strings (o Symbols) y los valores pueden ser cualquier tipo.\n\n```js\nlet persona = {\n  nombre: 'Ana',\n  edad: 30,\n  ciudad: 'Madrid'\n};\n\nconsole.log(persona.nombre);  // 'Ana'\nconsole.log(persona['edad']); // 30 (notación de corchete)\n```\n\n**Notación de punto vs corchete**:\n```js\nlet usuario = { nombre: 'Luis', 'edad-usuario': 25 };\n\nconsole.log(usuario.nombre);       // punto (preferida)\nconsole.log(usuario['edad-usuario']); // corchete (para claves con guiones)\n\nlet clave = 'nombre';\nconsole.log(usuario[clave]);       // 'Luis' (variable como clave)\n```\n\n**Agregar y modificar propiedades**:\n```js\nlet producto = { nombre: 'Laptop', precio: 1200 };\nproducto.disponible = true;      // agregar propiedad\nproducto.precio = 1100;          // modificar propiedad\ndelete producto.disponible;      // eliminar propiedad\n```\n\n**Recorrer objetos**:\n```js\nfor (let clave in persona) {\n  console.log(clave, persona[clave]);\n}\n\n// Obtener claves y valores\nconsole.log(Object.keys(persona));   // ['nombre', 'edad', 'ciudad']\nconsole.log(Object.values(persona)); // ['Ana', 30, 'Madrid']\n```\n\n**Métodos en objetos** (propiedades que son funciones):\n```js\nlet calculadora = {\n  a: 0,\n  b: 0,\n  sumar() { return this.a + this.b; },\n  multiplicar() { return this.a * this.b; }\n};\n```\n\n**Buenas prácticas**:\n- Usa nombres de clave descriptivos en camelCase\n- `const` en objetos evita reasignar la variable, pero el contenido sí puede cambiar\n- Usa notación de punto por defecto; corchete solo cuando necesites claves dinámicas", "exercise": "Crea un objeto `estudiante` con `nombre`, `edad`, `curso` y un método `presentarse()` que retorne 'Soy [nombre], tengo [edad] años y curso [curso]'. Declara `info` con el resultado de llamar a `estudiante.presentarse()`.", "solution": "let estudiante = {\n  nombre: 'Carlos',\n  edad: 22,\n  curso: 'JavaScript',\n  presentarse() {\n    return `Soy ${this.nombre}, tengo ${this.edad} años y curso ${this.curso}`;\n  }\n};\nlet info = estudiante.presentarse();", "tests": ["typeof estudiante === 'object'", "typeof estudiante.presentarse === 'function'", "info === 'Soy Carlos, tengo 22 años y curso JavaScript'"] },
  { "id": 23, "module": "Arrays y Objetos", "title": "Destructuring", "theory": "**Destructuring** (desestructuración) extrae valores de arrays u objetos en variables de forma concisa.\n\n```js\n// Destructuring de objetos\nconst persona = { nombre: 'Ana', edad: 30, ciudad: 'Madrid' };\nconst { nombre, edad } = persona;\nconsole.log(nombre); // 'Ana'\nconsole.log(edad);   // 30\n```\n\n**Renombrar variables**:\n```js\nconst { nombre: nom, edad: años } = persona;\nconsole.log(nom);  // 'Ana'\nconsole.log(años); // 30\n```\n\n**Valores por defecto**:\n```js\nconst { pais = 'Desconocido', ciudad } = persona;\nconsole.log(pais);   // 'Desconocido' (valor por defecto)\n```\n\n**Destructuring de arrays**:\n```js\nconst colores = ['rojo', 'verde', 'azul'];\nconst [primero, segundo] = colores;\nconsole.log(primero); // 'rojo'\nconsole.log(segundo); // 'verde'\n\n// Saltar elementos\nconst [primer, , tercero] = colores;\nconsole.log(tercero); // 'azul'\n\n// Resto con spread\nconst [head, ...tail] = [1, 2, 3, 4];\nconsole.log(head); // 1\nconsole.log(tail); // [2, 3, 4]\n```\n\n**Anidado**:\n```js\nconst usuario = { id: 1, datos: { nombre: 'Luis', edad: 25 } };\nconst { datos: { nombre } } = usuario;\nconsole.log(nombre); // 'Luis'\n```\n\n**En parámetros de función**:\n```js\nfunction mostrar({ nombre, edad }) {\n  console.log(`${nombre} tiene ${edad} años`);\n}\nmostrar(persona);\n```\n\n**Buenas prácticas**:\n- Destructuring hace el código más legible al extraer solo lo necesario\n- Úsalo en parámetros de función para recibir objetos con nombre\n- Combina con valores por defecto para evitar undefined", "exercise": "Dado `let datos = { id: 5, nombre: 'Marta', edad: 28, pais: 'Chile', ciudad: 'Santiago' }`, extrae `nombre` (renombrado a `usuario`), `pais` y `edad`. Luego extrae los valores restantes en un objeto llamado `resto` usando spread.", "solution": "let datos = { id: 5, nombre: 'Marta', edad: 28, pais: 'Chile', ciudad: 'Santiago' };\nlet { nombre: usuario, pais, edad, ...resto } = datos;", "tests": ["usuario === 'Marta'", "pais === 'Chile'", "edad === 28", "resto.id === 5", "resto.ciudad === 'Santiago'"] },
  { "id": 24, "module": "Arrays y Objetos", "title": "Spread operator", "theory": "El **spread operator** (`...`) expande elementos de un array o propiedades de un objeto. Es útil para copiar, combinar y pasar argumentos.\n\n```js\n// Spread en arrays\nconst arr1 = [1, 2, 3];\nconst arr2 = [...arr1, 4, 5];  // [1, 2, 3, 4, 5] (copia + añade)\nconst copia = [...arr1];       // [1, 2, 3] (copia superficial)\n\n// Combinar arrays\nconst a = [1, 2];\nconst b = [3, 4];\nconst combinado = [...a, ...b]; // [1, 2, 3, 4]\n```\n\n**Spread en objetos** (ES2018):\n```js\nconst obj1 = { a: 1, b: 2 };\nconst obj2 = { c: 3, ...obj1 }; // { c: 3, a: 1, b: 2 }\nconst fusion = { ...obj1, ...obj2 }; // combina objetos\n\n// Sobrescribir propiedades\nconst usuario = { nombre: 'Ana', edad: 30 };\nconst actualizado = { ...usuario, edad: 31 }; // { nombre: 'Ana', edad: 31 }\n```\n\n**Rest parameters** (en funciones, recoge argumentos):\n```js\nfunction sumarTodos(...numeros) {\n  return numeros.reduce((acc, n) => acc + n, 0);\n}\nconsole.log(sumarTodos(1, 2, 3, 4)); // 10\n```\n\n**Spread para pasar argumentos**:\n```js\nconst nums = [3, 7, 2];\nconsole.log(Math.max(...nums)); // 7 (equivalente a Math.max(3, 7, 2))\n```\n\n**Buenas prácticas**:\n- Usa spread para copiar arrays en vez de métodos mutables como `splice`\n- El spread hace copia superficial (shallow). Para objetos anidados necesitas clonación profunda\n- En objetos, las propiedades que aparecen después sobrescriben a las anteriores\n- Útil para crear versiones actualizadas de objetos sin mutar el original", "exercise": "Declara `base = [1, 2, 3]` y `extra = [4, 5]`. Usa spread para crear `todos` que combine ambos. Luego crea `objetoBase = {x: 10, y: 20}` y `objetoFinal = { ...objetoBase, z: 30, x: 99 }` (x se sobrescribe). Declara `maximo = Math.max(...todos)`.", "solution": "let base = [1, 2, 3];\nlet extra = [4, 5];\nlet todos = [...base, ...extra];\nlet objetoBase = {x: 10, y: 20};\nlet objetoFinal = { ...objetoBase, z: 30, x: 99 };\nlet maximo = Math.max(...todos);", "tests": ["todos.length === 5", "todos[0] === 1", "todos[4] === 5", "maximo === 5", "objetoFinal.x === 99", "objetoFinal.y === 20"] },
  { "id": 25, "module": "DOM y Eventos", "title": "Selección de elementos", "theory": "**`document.querySelector()`** selecciona el primer elemento que coincida con un selector CSS. **`querySelectorAll()`** selecciona todos y devuelve un NodeList.\n\n```js\n// Seleccionar por etiqueta, clase o id\nconst header = document.querySelector('header');\nconst boton = document.querySelector('.btn-primary');\nconst logo = document.querySelector('#logo');\n\n// Seleccionar todos\nconst items = document.querySelectorAll('.menu-item');\nconsole.log(items.length); // número de elementos\n```\n\n**Selectores CSS avanzados**:\n```js\ndocument.querySelector('ul li:first-child');\ndocument.querySelector('input[type=\"text\"]');\ndocument.querySelector('div > p');\ndocument.querySelectorAll('.lista > li');\n```\n\n**NodeList vs Array**: `querySelectorAll` devuelve un NodeList, no un Array. Para usar `map`, `filter`, `reduce`, conviértelo primero:\n```js\nconst divs = document.querySelectorAll('div');\nconst textos = Array.from(divs).map(d => d.textContent);\n// o: const textos = [...divs].map(d => d.textContent);\n```\n\n**Buenas prácticas**:\n- **Cachea** las selecciones si usas el mismo elemento varias veces (guarda en variable)\n- Usa selectores específicos para evitar seleccionar elementos no deseados\n- `querySelector` lanza error si el selector es inválido, pero devuelve `null` si no encuentra\n- Para IDs, `getElementById` es más rápido que `querySelector('#id')`", "exercise": "Dado el HTML `<ul id='lista'><li class='item'>A</li><li class='item'>B</li><li class='item'>C</li></ul>`, crea una función `contarItems` que haga querySelectorAll de '.item' y retorne la cantidad.", "solution": "function contarItems() {\n  return document.querySelectorAll('.item').length;\n}", "tests": ["typeof contarItems === 'function'"] },
  { "id": 26, "module": "DOM y Eventos", "title": "Modificación del DOM", "theory": "**`document.createElement()`** crea nuevos elementos HTML. **`textContent`** asigna o lee texto. **`appendChild()`** inserta un elemento como hijo.\n\n```js\n// Crear elemento\nconst nuevoDiv = document.createElement('div');\n\n// Asignar contenido\nnuevoDiv.textContent = 'Hola, soy un nuevo div';\n\n// Agregar al DOM\ndocument.body.appendChild(nuevoDiv);\n```\n\n**Atributos y clases**:\n```js\nconst img = document.createElement('img');\nimg.src = 'foto.jpg';\nimg.alt = 'Descripción';\nimg.className = 'imagen-perfil';\nimg.id = 'avatar';\n\nconst enlace = document.createElement('a');\nenlace.href = 'https://ejemplo.com';\nenlace.textContent = 'Visitar sitio';\n```\n\n**Insertar en posiciones específicas**:\n```js\nconst lista = document.querySelector('ul');\nconst item = document.createElement('li');\nitem.textContent = 'Nuevo item';\n\nlista.appendChild(item);           // al final\nlista.prepend(item);               // al inicio\nlista.insertBefore(item, ref);     // antes de ref\n```\n\n**innerHTML** (usar con precaución):\n```js\n// Más cómodo pero inseguro (riesgo XSS)\ncontenedor.innerHTML = '<p>Nuevo <strong>contenido</strong></p>';\n\n// Seguro (solo texto)\ncontenedor.textContent = '<p>No interpreta HTML</p>';\n```\n\n**Buenas prácticas**:\n- Usa `textContent` en vez de `innerHTML` para texto seguro\n- Crea primero los elementos, configúralos, y al final agrégalos al DOM\n- Múltiples inserciones → usa `DocumentFragment` para mejor rendimiento\n- Para eliminar: `elemento.remove()`", "exercise": "Crea una función `crearLista` que reciba un array de strings y cree un `<ul>` con un `<li>` por cada string (usando `createElement`, `textContent` y `appendChild`). Retorna el `ul` creado.", "solution": "function crearLista(items) {\n  const ul = document.createElement('ul');\n  for (let item of items) {\n    const li = document.createElement('li');\n    li.textContent = item;\n    ul.appendChild(li);\n  }\n  return ul;\n}", "tests": ["typeof crearLista === 'function'"] },
  { "id": 27, "module": "DOM y Eventos", "title": "Eventos", "theory": "Los **eventos** permiten que el código responda a interacciones del usuario: clics, teclado, mouse, formularios, etc.\n\n```js\nconst boton = document.querySelector('button');\n\nboton.addEventListener('click', function() {\n  alert('¡Botón clickeado!');\n});\n\n// Con arrow function\nboton.addEventListener('click', () => {\n  console.log('Click recibido');\n});\n```\n\n**El objeto `event`**:\n```js\nboton.addEventListener('click', (event) => {\n  console.log(event.type);    // 'click'\n  console.log(event.target);  // elemento que disparó el evento\n  console.log(event.clientX); // coordenada X del mouse\n});\n```\n\n**Eventos comunes**:\n```js\n// Ratón\nelemento.addEventListener('click', fn);\nelemento.addEventListener('dblclick', fn);\nelemento.addEventListener('mouseenter', fn);\nelemento.addEventListener('mouseleave', fn);\n\n// Teclado\ndocument.addEventListener('keydown', (e) => {\n  console.log(e.key);     // tecla presionada\n  console.log(e.code);    // código físico de la tecla\n});\n\n// Formulario\nformulario.addEventListener('submit', (e) => {\n  e.preventDefault();     // evita recargar la página\n});\n```\n\n**Delegación de eventos**: para manejar eventos en elementos dinámicos:\n```js\n// En vez de agregar listener a cada item:\ndocument.querySelector('ul').addEventListener('click', (e) => {\n  if (e.target.tagName === 'LI') {\n    console.log('Clickeaste:', e.target.textContent);\n  }\n});\n```\n\n**Buenas prácticas**:\n- Usa siempre `addEventListener`, no `onclick` (permite múltiples listeners)\n- Elimina listeners que ya no necesitas con `removeEventListener`\n- Usa `e.preventDefault()` o `e.stopPropagation()` cuando sea necesario\n- La delegación mejora rendimiento con muchos elementos", "exercise": "Crea una función `agregarListenerMultiple` que reciba un selector CSS (`selector`) y un tipo de evento (`tipo`). Usa `querySelectorAll` para seleccionar todos los elementos que coincidan y agregar el listener especificado. El callback debe mostrar un `console.log` con el texto del elemento clickeado.", "solution": "function agregarListenerMultiple(selector, tipo) {\n  const elementos = document.querySelectorAll(selector);\n  elementos.forEach(el => {\n    el.addEventListener(tipo, (e) => console.log(e.target.textContent));\n  });\n}", "tests": ["typeof agregarListenerMultiple === 'function'"] },
  { "id": 28, "module": "DOM y Eventos", "title": "Mini-app de notas", "theory": "Crea una mini-aplicación de notas combinando objetos, arrays, DOM y eventos. El patrón típico: **estado** (datos) + **render** (actualizar UI) + **eventos** (interacción).\n\n```js\n// Estado\nlet notas = [];\n\n// CRUD: Create, Read, Update, Delete\nfunction agregarNota(texto) {\n  const nota = { id: Date.now(), texto, fecha: new Date() };\n  notas.push(nota);\n  renderizarNotas();\n  return nota;\n}\n\nfunction eliminarNota(id) {\n  notas = notas.filter(n => n.id !== id);\n  renderizarNotas();\n}\n\n// Render\nfunction renderizarNotas() {\n  const contenedor = document.querySelector('#lista-notas');\n  contenedor.innerHTML = '';\n  \n  for (const nota of notas) {\n    const div = document.createElement('div');\n    div.className = 'nota';\n    div.textContent = nota.texto;\n    \n    const btnEliminar = document.createElement('button');\n    btnEliminar.textContent = 'X';\n    btnEliminar.onclick = () => eliminarNota(nota.id);\n    \n    div.appendChild(btnEliminar);\n    contenedor.appendChild(div);\n  }\n}\n```\n\n**Buenas prácticas**:\n- Separa la lógica de negocio (CRUD) de la manipulación del DOM\n- Actualiza el DOM solo después de modificar el estado\n- Usa IDs únicos (Date.now() o crypto.randomUUID()) para identificar cada nota\n- El render debe ser **idempotente**: puede llamarse múltiples veces sin efectos secundarios\n- El patrón estado → render → eventos se usa en frameworks modernos como React y Vue", "exercise": "Declara `let tareas = []`. Crea funciones `agregarTarea(texto)` (agrega con `{id, texto, completada: false}`) y `completarTarea(id)` (cambia `completada` a `true`). Crea también `obtenerPendientes` que filtre las no completadas con `filter`.", "solution": "let tareas = [];\nfunction agregarTarea(texto) {\n  const tarea = { id: Date.now(), texto, completada: false };\n  tareas.push(tarea);\n  return tarea;\n}\nfunction completarTarea(id) {\n  const tarea = tareas.find(t => t.id === id);\n  if (tarea) tarea.completada = true;\n}\nfunction obtenerPendientes() {\n  return tareas.filter(t => !t.completada);\n}", "tests": ["typeof agregarTarea === 'function'", "typeof completarTarea === 'function'", "typeof obtenerPendientes === 'function'"] },
  { "id": 29, "module": "Asincronía", "title": "Callbacks y Promesas", "theory": "Las **Promesas** representan un valor futuro: pueden estar **pendiente** (pending), **resuelta** (fulfilled) o **rechazada** (rejected).\n\n```js\nconst promesa = new Promise((resolve, reject) => {\n  setTimeout(() => {\n    resolve('Operación completada');\n    // reject(new Error('Algo salió mal'));\n  }, 1000);\n});\n\npromesa.then(resultado => console.log(resultado));\npromesa.catch(error => console.error(error));\npromesa.finally(() => console.log('Siempre se ejecuta'));\n```\n\n**Encadenar promesas**:\n```js\nnew Promise(resolve => resolve(5))\n  .then(n => n * 2)\n  .then(n => n + 1)\n  .then(n => console.log(n)); // 11\n```\n\n**Promise.all**: ejecuta varias promesas en paralelo y espera todas:\n```js\nconst p1 = Promise.resolve(1);\nconst p2 = Promise.resolve(2);\nconst p3 = new Promise(resolve => setTimeout(() => resolve(3), 100));\n\nPromise.all([p1, p2, p3]).then(resultados => {\n  console.log(resultados); // [1, 2, 3]\n});\n```\n\n**Promise.race**: la primera que se resuelva o rechace gana.\n\n**Callback vs Promesa**:\n```js\n// Callback (callback hell)\nobtenerUsuario(1, usuario => {\n  obtenerPedidos(usuario.id, pedidos => {\n    obtenerDetalle(pedidos[0].id, detalle => {\n      console.log(detalle);\n    });\n  });\n});\n\n// Promesa (mucho más plano)\nobtenerUsuario(1)\n  .then(usuario => obtenerPedidos(usuario.id))\n  .then(pedidos => obtenerDetalle(pedidos[0].id))\n  .then(detalle => console.log(detalle))\n  .catch(error => console.error(error));\n```", "exercise": "Crea una función `simularPeticion(exito)` que retorne una Promise. Si `exito` es true, se resuelve tras 100ms con 'Datos recibidos'. Si es false, se rechaza tras 100ms con 'Error en la petición'.", "solution": "function simularPeticion(exito) {\n  return new Promise((resolve, reject) => {\n    setTimeout(() => {\n      if (exito) resolve('Datos recibidos');\n      else reject('Error en la petición');\n    }, 100);\n  });\n}", "tests": ["typeof simularPeticion === 'function'"] },
  { "id": 30, "module": "Asincronía", "title": "Fetch API", "theory": "**`fetch()`** realiza peticiones HTTP. Devuelve una Promesa que se resuelve con un objeto **Response**. Para obtener los datos JSON, usa `.json()`.\n\n```js\nfetch('https://api.ejemplo.com/usuarios')\n  .then(response => {\n    if (!response.ok) {\n      throw new Error('Error HTTP: ' + response.status);\n    }\n    return response.json();\n  })\n  .then(data => console.log(data))\n  .catch(error => console.error('Fetch falló:', error));\n```\n\n**Métodos HTTP**:\n```js\n// GET (por defecto)\nfetch('url/api')\n\n// POST\nfetch('url/api', {\n  method: 'POST',\n  headers: { 'Content-Type': 'application/json' },\n  body: JSON.stringify({ nombre: 'Ana', edad: 30 })\n})\n```\n\n**Response.ok y status codes**:\n```js\nfetch(url).then(res => {\n  if (res.ok) {             // status 200-299\n    return res.json();\n  } else if (res.status === 404) {\n    console.log('No encontrado');\n  } else if (res.status === 500) {\n    console.log('Error del servidor');\n  }\n});\n```\n\n**Errores comunes**:\n- `fetch` solo rechaza por errores de red, NO por códigos HTTP 4xx/5xx\n- Siempre verifica `response.ok` o `response.status`\n- No olvides el `return response.json()` dentro del `then`\n- `response.json()` también devuelve una Promesa", "exercise": "Crea una función `obtenerUsuarioPorId(id)` que simule una petición usando `Promise.resolve`. Debe retornar una promesa que se resuelva con `{ id, nombre: 'Usuario ' + id, email: 'usuario' + id + '@test.com' }`.", "solution": "function obtenerUsuarioPorId(id) {\n  return Promise.resolve({\n    id,\n    nombre: 'Usuario ' + id,\n    email: 'usuario' + id + '@test.com'\n  });\n}", "tests": ["typeof obtenerUsuarioPorId === 'function'"] },
  { "id": 31, "module": "Asincronía", "title": "async/await", "theory": "**`async/await`** es azúcar sintáctico sobre Promesas. Una función `async` siempre devuelve una Promesa. `await` pausa la ejecución hasta que la Promesa se resuelva.\n\n```js\nasync function obtenerDatos() {\n  const respuesta = await fetch('url/api');\n  const datos = await respuesta.json();\n  return datos;\n}\n\n// Equivalente con .then()\nfunction obtenerDatosThen() {\n  return fetch('url/api').then(r => r.json());\n}\n```\n\n**Manejo de errores con try/catch**:\n```js\nasync function obtenerUsuario(id) {\n  try {\n    const res = await fetch(`/api/usuarios/${id}`);\n    if (!res.ok) throw new Error('Usuario no encontrado');\n    const usuario = await res.json();\n    return usuario;\n  } catch (error) {\n    console.error('Error:', error.message);\n    return null;\n  }\n}\n```\n\n**Ejecución paralela con Promise.all**:\n```js\nasync function obtenerTodo() {\n  const [usuarios, productos, pedidos] = await Promise.all([\n    fetch('/api/usuarios').then(r => r.json()),\n    fetch('/api/productos').then(r => r.json()),\n    fetch('/api/pedidos').then(r => r.json())\n  ]);\n  \n  return { usuarios, productos, pedidos };\n}\n```\n\n**Reglas importantes**:\n- `await` solo puede usarse dentro de funciones `async`\n- `async` function siempre devuelve una Promesa (aunque retornes un valor simple)\n- Si una Promesa se rechaza y no hay `catch`, `await` lanza la excepción\n- Para ejecución en paralelo usa `Promise.all`, no `await` secuencial", "exercise": "Crea una función async `procesarEnCadena` que reciba un número. Usa `await` para simular tres operaciones asíncronas (cada una con `Promise.resolve` tras 0ms): primero suma 10, luego multiplica por 2, luego resta 5. Retorna el resultado final.", "solution": "async function procesarEnCadena(n) {\n  const paso1 = await Promise.resolve(n + 10);\n  const paso2 = await Promise.resolve(paso1 * 2);\n  const paso3 = await Promise.resolve(paso2 - 5);\n  return paso3;\n}", "tests": ["typeof procesarEnCadena === 'function'"] },
  { "id": 32, "module": "Programación Avanzada", "title": "Clases y POO", "theory": "Las **clases** (ES6) son plantillas para crear objetos. Encapsulan datos (propiedades) y comportamiento (métodos).\n\n```js\nclass Persona {\n  constructor(nombre, edad) {\n    this.nombre = nombre;\n    this.edad = edad;\n  }\n\n  saludar() {\n    return `Hola, soy ${this.nombre}`;\n  }\n\n  cumpleanios() {\n    this.edad++;\n  }\n}\n\nconst ana = new Persona('Ana', 30);\nconsole.log(ana.saludar()); // 'Hola, soy Ana'\n```\n\n**Propiedades privadas** (ES2020 con `#`):\n```js\nclass CuentaBancaria {\n  #saldo = 0;  // propiedad privada\n\n  constructor(titular) {\n    this.titular = titular;\n  }\n\n  depositar(monto) {\n    if (monto > 0) this.#saldo += monto;\n  }\n\n  obtenerSaldo() {\n    return this.#saldo;\n  }\n}\n```\n\n**Getters y Setters**:\n```js\nclass Rectangulo {\n  constructor(ancho, alto) {\n    this.ancho = ancho;\n    this.alto = alto;\n  }\n\n  get area() {\n    return this.ancho * this.alto;\n  }\n\n  set dimensiones({ ancho, alto }) {\n    this.ancho = ancho;\n    this.alto = alto;\n  }\n}\n\nconst r = new Rectangulo(5, 10);\nconsole.log(r.area); // 50 (getter, sin paréntesis)\n```\n\n**Métodos estáticos**: pertenecen a la clase, no a la instancia:\n```js\nclass Util {\n  static formatearFecha(fecha) {\n    return fecha.toISOString().split('T')[0];\n  }\n}\nconsole.log(Util.formatearFecha(new Date()));\n```", "exercise": "Crea una clase `Contador` con `#valor` privado inicializado en 0. Métodos: `incrementar()` (aumenta en 1), `decrementar()` (disminuye en 1), `obtenerValor()` (retorna #valor) y un getter `valorDoble` que retorne #valor * 2.", "solution": "class Contador {\n  #valor = 0;\n  incrementar() { this.#valor++; }\n  decrementar() { this.#valor--; }\n  obtenerValor() { return this.#valor; }\n  get valorDoble() { return this.#valor * 2; }\n}", "tests": ["typeof Contador === 'function'", "typeof new Contador().incrementar === 'function'", "typeof new Contador().obtenerValor === 'function'"] },
  { "id": 33, "module": "Programación Avanzada", "title": "Herencia y Prototipos", "theory": "La **herencia** permite que una clase (hija) herede propiedades y métodos de otra (padre) usando **`extends`** y **`super`**.\n\n```js\nclass Animal {\n  constructor(nombre) {\n    this.nombre = nombre;\n  }\n\n  hablar() {\n    return 'Hace un sonido';\n  }\n}\n\nclass Perro extends Animal {\n  constructor(nombre, raza) {\n    super(nombre);  // llama al constructor padre\n    this.raza = raza;\n  }\n\n  hablar() {  // sobrescribe (override)\n    return '¡Guau!';\n  }\n}\n\nconst luna = new Perro('Luna', 'Labrador');\nconsole.log(luna.hablar()); // '¡Guau!'\nconsole.log(luna.nombre);   // 'Luna' (heredado)\n```\n\n**`instanceof`**: verifica si un objeto es instancia de una clase:\n```js\nconsole.log(luna instanceof Perro);  // true\nconsole.log(luna instanceof Animal); // true\nconsole.log(luna instanceof Object); // true\n```\n\n**Cadena de prototipos**: cuándo llamar a `super`:\n- En el constructor hijo: `super(...)` debe llamarse antes de usar `this`\n- En métodos: `super.metodoPadre()` para invocar la versión padre\n\n```js\nclass Gato extends Animal {\n  constructor(nombre, color) {\n    super(nombre);\n    this.color = color;\n  }\n\n  hablar() {\n    return super.hablar() + ' pero específicamente ¡Miau!';\n  }\n}\n```\n\n**Buenas prácticas**:\n- Prefiere composición sobre herencia (`tiene-un` vs `es-un`)\n- La jerarquía de herencia profunda (> 3 niveles) es difícil de mantener\n- Usa `super` en el constructor hijo siempre, incluso si el padre no tiene parámetros\n- `instanceof` funciona con clases que extienden de otras", "exercise": "Crea una clase `Figura` con constructor `(nombre)` y método `area()` que retorne 0. Crea `Circulo` que extienda `Figura`, reciba `radio` en el constructor, llame a `super('Círculo')` y sobreescriba `area()` retornando `Math.PI * radio * radio`.", "solution": "class Figura {\n  constructor(nombre) { this.nombre = nombre; }\n  area() { return 0; }\n}\nclass Circulo extends Figura {\n  constructor(radio) {\n    super('Círculo');\n    this.radio = radio;\n  }\n  area() { return Math.PI * this.radio * this.radio; }\n}", "tests": ["typeof Circulo === 'function'", "new Circulo(5) instanceof Figura"] },
  { "id": 34, "module": "Programación Avanzada", "title": "Closures", "theory": "Un **closure** es una función que recuerda el ámbito (scope) donde fue creada, incluso después de que ese ámbito haya terminado. Permite encapsular datos privados.\n\n```js\nfunction crearContador() {\n  let count = 0;  // variable privada\n\n  return {\n    incrementar() {\n      count++;\n      return count;\n    },\n    decrementar() {\n      count--;\n      return count;\n    },\n    obtenerValor() {\n      return count;\n    }\n  };\n}\n\nconst contador = crearContador();\nconsole.log(contador.incrementar()); // 1\nconsole.log(contador.incrementar()); // 2\nconsole.log(contador.obtenerValor()); // 2\n// count no es accesible directamente\n```\n\n**Closures en bucles** (problema clásico):\n```js\n// Problema: todas imprimen 3\nfor (var i = 0; i < 3; i++) {\n  setTimeout(() => console.log(i), 100); // 3, 3, 3\n}\n\n// Solución con closure usando let\nfor (let i = 0; i < 3; i++) {\n  setTimeout(() => console.log(i), 100); // 0, 1, 2\n}\n\n// Solución clásica con IIFE\nfor (var i = 0; i < 3; i++) {\n  (function(j) {\n    setTimeout(() => console.log(j), 100); // 0, 1, 2\n  })(i);\n}\n```\n\n**Factory functions con closures**:\n```js\nfunction crearSaludo(idioma) {\n  return function(nombre) {\n    if (idioma === 'es') return `Hola, ${nombre}`;\n    if (idioma === 'en') return `Hello, ${nombre}`;\n    return nombre;\n  };\n}\n\nconst saludarES = crearSaludo('es');\nconst saludarEN = crearSaludo('en');\nconsole.log(saludarES('Ana')); // 'Hola, Ana'\nconsole.log(saludarEN('Ana')); // 'Hello, Ana'\n```\n\n**Usos prácticos**:\n- Encapsulación (variables privadas)\n- Memoización (cachear resultados)\n- Funciones parciales (fijar argumentos)\n- Módulos (patrón IIFE)", "exercise": "Crea una función `crearAcumulador` que reciba un valor inicial. Debe retornar una función que reciba un número y lo sume al acumulador, retornando el nuevo total. El acumulador debe ser privado.", "solution": "function crearAcumulador(inicial) {\n  let total = inicial;\n  return function(n) {\n    total += n;\n    return total;\n  };\n}", "tests": ["typeof crearAcumulador === 'function'", "typeof crearAcumulador(0) === 'function'"] },
  { "id": 35, "module": "Programación Avanzada", "title": "Patrones de Diseño", "theory": "Los **patrones de diseño** son soluciones reutilizables para problemas comunes. Los más útiles en JavaScript:\n\n**Factory**: crea objetos sin especificar la clase exacta:\n```js\nfunction crearVehiculo(tipo) {\n  switch(tipo) {\n    case 'coche': return { ruedas: 4, tipo: 'Coche', arrancar() { return 'Vroom'; } };\n    case 'moto': return { ruedas: 2, tipo: 'Moto', arrancar() { return 'Ring ring'; } };\n    default: return { ruedas: 0, tipo: 'Desconocido', arrancar() { return '...'; } };\n  }\n}\n```\n\n**Observer (o Pub/Sub)**: un objeto notifica a múltiples suscriptores cuando cambia:\n```js\nclass EventEmitter {\n  constructor() {\n    this.eventos = {};\n  }\n\n  on(evento, callback) {\n    if (!this.eventos[evento]) this.eventos[evento] = [];\n    this.eventos[evento].push(callback);\n  }\n\n  emit(evento, ...args) {\n    const callbacks = this.eventos[evento];\n    if (callbacks) callbacks.forEach(cb => cb(...args));\n  }\n}\n```\n\n**Singleton**: asegura una única instancia:\n```js\nclass Configuracion {\n  static #instancia;\n\n  constructor() {\n    if (Configuracion.#instancia) return Configuracion.#instancia;\n    this.config = {};\n    Configuracion.#instancia = this;\n  }\n}\n```\n\n**Buenas prácticas**:\n- No forces patrones donde no hacen falta. A veces una función basta\n- Los patrones son guías, no reglas estrictas\n- En JS, muchos patrones se implementan más simple gracias a closures, objetos literales y funciones de primera clase", "exercise": "Crea una factory function `crearEmpleado(tipo)` que retorne: si es 'developer' → `{rol:'Developer', lenguaje:'JavaScript', trabajar(){return 'Escribiendo código'}}`; si es 'manager' → `{rol:'Manager', equipo:[], trabajar(){return 'Gestionando equipo'}}`.", "solution": "function crearEmpleado(tipo) {\n  if (tipo === 'developer') {\n    return { rol: 'Developer', lenguaje: 'JavaScript', trabajar() { return 'Escribiendo código'; } };\n  }\n  if (tipo === 'manager') {\n    return { rol: 'Manager', equipo: [], trabajar() { return 'Gestionando equipo'; } };\n  }\n  return { rol: 'Desconocido', trabajar() { return 'Sin tareas'; } };\n}", "tests": ["typeof crearEmpleado === 'function'", { "type": "function", "code": "crearEmpleado('developer').trabajar()", "expected": "Escribiendo código" }] },
  { "id": 36, "module": "Programación Avanzada", "title": "Simulador de tienda online", "theory": "Combinamos varios conceptos (clases, arrays, métodos) para simular un carrito de compras.\n\n```js\nclass Producto {\n  constructor(nombre, precio, categoria) {\n    this.nombre = nombre;\n    this.precio = precio;\n    this.categoria = categoria;\n    this.id = Date.now();\n  }\n}\n\nclass Carrito {\n  constructor() {\n    this.items = [];\n  }\n\n  agregar(producto) {\n    this.items.push(producto);\n  }\n\n  eliminar(id) {\n    this.items = this.items.filter(item => item.id !== id);\n  }\n\n  total() {\n    return this.items.reduce((suma, item) => suma + item.precio, 0);\n  }\n\n  resumen() {\n    return this.items.map(p => `${p.nombre}: $${p.precio}`);\n  }\n\n  // Descuento por categoría\n  aplicarDescuento(categoria, porcentaje) {\n    this.items.forEach(item => {\n      if (item.categoria === categoria) {\n        item.precio *= (1 - porcentaje / 100);\n      }\n    });\n  }\n}\n\n// Uso\nconst carrito = new Carrito();\ncarrito.agregar(new Producto('Laptop', 1200, 'electrónica'));\ncarrito.agregar(new Producto('Mouse', 25, 'electrónica'));\ncarrito.aplicarDescuento('electrónica', 10);\nconsole.log(carrito.total()); // (1200 + 25) * 0.9\n```\n\n**Buenas prácticas**:\n- Cada clase tiene una responsabilidad clara\n- Los métodos modifican el estado interno del objeto\n- `reduce` es ideal para cálculos acumulativos como totales\n- Usa `filter` para eliminar, no modifiques el array mientras lo recorres", "exercise": "Crea una clase `Carrito` con constructor que inicialice `items = []`. Métodos: `agregar(producto)` (push), `eliminar(id)` (filter), `total()` (reduce suma precios) y `cantidad()` que retorne la longitud de items. Crea una clase `Producto` con `(nombre, precio)`.", "solution": "class Producto {\n  constructor(nombre, precio) {\n    this.nombre = nombre;\n    this.precio = precio;\n    this.id = Date.now();\n  }\n}\nclass Carrito {\n  constructor() { this.items = []; }\n  agregar(p) { this.items.push(p); }\n  eliminar(id) { this.items = this.items.filter(i => i.id !== id); }\n  total() { return this.items.reduce((s, i) => s + i.precio, 0); }\n  cantidad() { return this.items.length; }\n}", "tests": ["typeof Carrito === 'function'", "typeof Producto === 'function'"] },
  { "id": 37, "module": "Optimización y Buenas Prácticas", "title": "Optimización de funciones", "theory": "Optimizar no es solo velocidad: es escribir código claro, eficiente y mantenible.\n\n**`reduce` vs bucle for**: `reduce` es más declarativo y menos propenso a errores:\n```js\nconst nums = [1, 2, 3, 4, 5];\n\n// Bucle for (imperativo)\nlet sumaFor = 0;\nfor (let i = 0; i < nums.length; i++) {\n  sumaFor += nums[i];\n}\n\n// reduce (declarativo)\nconst sumaReduce = nums.reduce((acc, n) => acc + n, 0);\n```\n\n**Early return**: simplifica la lógica eliminando anidamiento:\n```js\n// Sin early return\nfunction validarUsuario(usuario) {\n  if (usuario) {\n    if (usuario.nombre) {\n      if (usuario.edad >= 18) {\n        return true;\n      }\n    }\n  }\n  return false;\n}\n\n// Con early return\nfunction validarUsuario(usuario) {\n  if (!usuario) return false;\n  if (!usuario.nombre) return false;\n  if (usuario.edad < 18) return false;\n  return true;\n}\n```\n\n**Cachear resultados** (memoización):\n```js\nfunction factorial(n, cache = {}) {\n  if (n in cache) return cache[n];\n  if (n <= 1) return 1;\n  cache[n] = n * factorial(n - 1, cache);\n  return cache[n];\n}\n```\n\n**Rendimiento**:\n- `for` clásico es el más rápido, pero `forEach`, `map`, `reduce` son más legibles\n- Para arrays grandes, elige legibilidad primero, optimiza solo si hay cuello de botella\n- Evita crear objetos/funciones innecesarias dentro de bucles\n- Usa `Set` para búsquedas rápidas sin duplicados", "exercise": "Crea una función `maximo` que reciba un array de números y retorne el máximo (sin usar Math.max). Usa `reduce`. Luego crea `sumaPares` que sume solo los números pares de un array usando `filter` y `reduce`.", "solution": "function maximo(arr) {\n  return arr.reduce((max, n) => n > max ? n : max, -Infinity);\n}\nfunction sumaPares(arr) {\n  return arr.filter(n => n % 2 === 0).reduce((a, b) => a + b, 0);\n}", "tests": [{ "type": "function", "code": "maximo([3, 7, 2, 9, 5])", "expected": 9 }, { "type": "function", "code": "maximo([-5, -2, -10])", "expected": -2 }, { "type": "function", "code": "sumaPares([1, 2, 3, 4, 5, 6])", "expected": 12 }] },
  { "id": 38, "module": "Optimización y Buenas Prácticas", "title": "Complejidad algorítmica", "theory": "La **complejidad algorítmica** (Big O) describe cómo crece el tiempo de ejecución al aumentar el tamaño de los datos.\n\n| Notación | Nombre | Ejemplo |\n|----------|--------|--------|\n| O(1) | Constante | Acceso por índice `arr[i]` |\n| O(log n) | Logarítmica | Búsqueda binaria |\n| O(n) | Lineal | Bucle simple `for` |\n| O(n log n) | Linealítmica | Ordenación eficiente |\n| O(n²) | Cuadrática | Bucles anidados |\n\n**Ejemplos**:\n```js\n// O(1) - constante\nfunction obtenerPrimero(arr) {\n  return arr[0];\n}\n\n// O(n) - lineal\nfunction buscar(arr, objetivo) {\n  for (let i = 0; i < arr.length; i++) {\n    if (arr[i] === objetivo) return i;\n  }\n  return -1;\n}\n\n// O(n²) - cuadrática\nfunction tieneDuplicados(arr) {\n  for (let i = 0; i < arr.length; i++) {\n    for (let j = i + 1; j < arr.length; j++) {\n      if (arr[i] === arr[j]) return true;\n    }\n  }\n  return false;\n}\n```\n\n**Optimizar búsquedas**: usar `Set` o `Map` para O(1) en lugar de O(n):\n```js\n// O(n) - array\nfunction existeEnArray(arr, valor) {\n  return arr.includes(valor);\n}\n\n// O(1) - Set\nfunction existeEnSet(set, valor) {\n  return set.has(valor);\n}\n```\n\n**Buenas prácticas**:\n- Empieza con la solución más simple (O(n) suele ser suficiente)\n- Optimiza solo cuando hay un problema de rendimiento medible\n- Usa `Set`/`Map` para búsquedas y eliminación de duplicados\n- Para arrays ordenados, búsqueda binaria (O(log n))", "exercise": "Crea una función `eliminarDuplicados` que reciba un array y retorne un nuevo array sin duplicados. Usa un `Set` para O(n) en vez de bucles anidados O(n²).", "solution": "function eliminarDuplicados(arr) {\n  return [...new Set(arr)];\n}", "tests": [{ "type": "function", "code": "JSON.stringify(eliminarDuplicados([1, 2, 2, 3, 3, 3, 4]))", "expected": "[1,2,3,4]" }, { "type": "function", "code": "JSON.stringify(eliminarDuplicados(['a', 'b', 'a', 'c']))", "expected": "[\"a\",\"b\",\"c\"]" }] },
  { "id": 39, "module": "Optimización y Buenas Prácticas", "title": "Testing básico", "theory": "Los **tests unitarios** verifican que funciones individuales se comporten correctamente. El patrón **AAA**: Arrange (preparar), Act (ejecutar), Assert (verificar).\n\n```js\n// Función a testear\nfunction sumar(a, b) {\n  return a + b;\n}\n\n// Test unitario con patrón AAA\nfunction testSuma() {\n  // Arrange (preparar)\n  const a = 2, b = 3;\n  const esperado = 5;\n\n  // Act (ejecutar)\n  const resultado = sumar(a, b);\n\n  // Assert (verificar)\n  if (resultado === esperado) {\n    console.log('✓ testSuma pasó');\n  } else {\n    console.error('✗ testSuma falló:', resultado, '!=', esperado);\n  }\n}\n```\n\n**Casos borde (edge cases)**:\n```js\nfunction dividir(a, b) {\n  if (b === 0) return Infinity;\n  return a / b;\n}\n\n// Tests\nconsole.log(dividir(10, 2) === 5);       // normal\nconsole.log(dividir(10, 0) === Infinity); // división por cero\nconsole.log(dividir(0, 10) === 0);        // cero dividido\nconsole.log(dividir(-10, 2) === -5);      // números negativos\n```\n\n**Tipos de tests**:\n```js\n// Test de igualdad\nfunction esMayorQue(a, b) { return a > b; }\nconsole.assert(esMayorQue(5, 3), '5 > 3 debería ser true');\n\n// Test de arrays\nfunction invertir(arr) { return arr.reverse(); }\nconsole.assert(JSON.stringify(invertir([1,2,3])) === '[3,2,1]');\n\n// Test de objetos\nfunction crearPersona(n) { return { nombre: n }; }\nconst p = crearPersona('Ana');\nconsole.assert(p.nombre === 'Ana', 'El nombre debería ser Ana');\n```\n\n**Buenas prácticas**:\n- Un test por comportamiento (no mezcles asserts de cosas distintas)\n- Prueba casos normales, casos borde y valores límite\n- Los tests deben ser deterministas (mismos input → mismo resultado)\n- No tests para funciones triviales (getters/setters sin lógica)", "exercise": "Crea una función `invertirArray` que reciba un array y retorne uno nuevo invertido (sin mutar el original). Luego crea una función `testInvertirArray` que verifique: (1) `[1,2,3]` invertido es `[3,2,1]`, (2) el array original no se modifica, (3) array vacío retorna array vacío. Debe devolver true si todos pasan.", "solution": "function invertirArray(arr) {\n  return [...arr].reverse();\n}\nfunction testInvertirArray() {\n  const original = [1, 2, 3];\n  const invertido = invertirArray(original);\n  const t1 = JSON.stringify(invertido) === '[3,2,1]';\n  const t2 = JSON.stringify(original) === '[1,2,3]';\n  const t3 = JSON.stringify(invertirArray([])) === '[]';\n  return t1 && t2 && t3;\n}", "tests": ["typeof invertirArray === 'function'", "typeof testInvertirArray === 'function'"] },
  { "id": 40, "module": "Proyectos Finales", "title": "Planificación de proyectos", "theory": "Planificar antes de codificar ahorra tiempo y evita frustraciones. Un buen plan incluye: **objetivos**, **requisitos**, **MVP**, **tareas** y **tecnologías**.\n\n```js\nconst proyecto = {\n  nombre: 'Gestor de Tareas',\n  objetivo: 'App web para crear y gestionar tareas personales',\n  tecnologias: ['HTML', 'CSS', 'JavaScript', 'LocalStorage'],\n  mvp: [\n    'Agregar tarea con texto',\n    'Marcar tarea como completada',\n    'Eliminar tarea'\n  ],\n  extras: ['Categorías', 'Filtros', 'Persistencia LocalStorage']\n};\n```\n\n**Metodología**:\n1. **Definir objetivo**: ¿qué problema resuelve?\n2. **Requisitos funcionales**: ¿qué debe hacer?\n3. **MVP** (Producto Mínimo Viable): la versión más simple que funciona\n4. **Dividir en tareas**: pequeñas, específicas, medibles\n5. **Elección técnica**: herramientas adecuadas\n\n**Ejemplo de desglose**:\n```js\nconst tareas = [\n  { id: 1, descripcion: 'Estructura HTML básica', completada: false },\n  { id: 2, descripcion: 'Estilos CSS responsivos', completada: false },\n  { id: 3, descripcion: 'Lógica JS: CRUD de tareas', completada: false },\n  { id: 4, descripcion: 'Persistencia LocalStorage', completada: false }\n];\n```\n\n**Proyectos sugeridos para practicar**:\n- **Juego Snake** con Canvas API\n- **SPA de notas** sin frameworks\n- **Dashboard** con datos mock y gráficos\n- **Clon de Trello** (Kanban con drag & drop)\n- **Buscador de películas** con API pública\n\n**Buenas prácticas**:\n- Empieza con el MVP, luego añade funcionalidades extra\n- Divide el proyecto en sprints/ciclos pequeños\n- Usa control de versiones (git) desde el inicio\n- Prueba cada funcionalidad antes de pasar a la siguiente\n- Documenta decisiones técnicas importantes", "exercise": "Declara un objeto `miProyecto` con: `nombre` (string), `objetivo` (string), `tecnologias` (array de strings), `modulos` (array de objetos con `{nombre, tareas:[]}`) y un método `agregarModulo(nombre, tareas)` que agregue un módulo al array modulos.", "solution": "let miProyecto = {\n  nombre: 'Mi Proyecto Final',\n  objetivo: 'Aplicación web interactiva',\n  tecnologias: ['HTML', 'CSS', 'JavaScript'],\n  modulos: [],\n  agregarModulo(nombre, tareas) {\n    this.modulos.push({ nombre, tareas });\n  }\n};", "tests": ["typeof miProyecto === 'object'", "typeof miProyecto.agregarModulo === 'function'"] },
  { "id": 41, "module": "JavaScript en el Mundo Real", "title": "Vite y npm scripts", "theory": "**Vite** es un bundler moderno que usamos en este proyecto. Proporciona un servidor de desarrollo con HMR (Hot Module Replacement) y build optimizado.\n\n**Scripts comunes en package.json**:\n```bash\nnpm run dev      # Inicia servidor de desarrollo con HMR\nnpm run build    # Compila y empaqueta para producción\nnpm run preview  # Previsualiza la build de producción\nnpm test         # Ejecuta tests\n```\n\n**Estructura de un proyecto Vite**:\n```\nmi-proyecto/\n├── index.html       # Entrada principal\n├── package.json     # Dependencias y scripts\n├── vite.config.ts   # Configuración de Vite\n├── tsconfig.json    # Configuración de TypeScript\n├── js/              # Código fuente\n│   └── app.ts\n└── dist/            # Build de producción (generado)\n```\n\n**Ejemplo de package.json**:\n```json\n{\n  \"name\": \"mi-app\",\n  \"scripts\": {\n    \"dev\": \"vite\",\n    \"build\": \"tsc --noEmit && vite build\",\n    \"preview\": \"vite preview\"\n  }\n}\n```\n\n**Buenas prácticas**:\n- Usa `node -v` y `npm -v` para verificar versiones\n- El script `dev` es para desarrollo, `build` para producción\n- `preview` sirve la carpeta `dist/` localmente para verificar antes de subir\n- Ignora `node_modules/` y `dist/` en tu repositorio (.gitignore)", "exercise": "Declara un objeto `packageInfo` con: `nombre` (string), `version` ('1.0.0'), `scripts` (objeto con 'dev', 'build', 'preview') y una función `correrScript(script)` que retorne 'Ejecutando ' + script + '...'.", "solution": "let packageInfo = {\n  nombre: 'mi-app',\n  version: '1.0.0',\n  scripts: {\n    dev: 'vite',\n    build: 'tsc --noEmit && vite build',\n    preview: 'vite preview'\n  },\n  correrScript(script) {\n    return 'Ejecutando ' + script + '...';\n  }\n};", "tests": ["typeof packageInfo === 'object'", "packageInfo.version === '1.0.0'", "typeof packageInfo.scripts === 'object'", "typeof packageInfo.correrScript === 'function'", { "type": "function", "code": "packageInfo.correrScript('dev')", "expected": "Ejecutando dev..." }] },
  { "id": 42, "module": "JavaScript en el Mundo Real", "title": "Despliegue en Netlify/Vercel", "theory": "**Desplegar** una app significa subirla a un servidor para que sea accesible públicamente. Servicios como Netlify y Vercel ofrecen hosting gratuito para apps estáticas.\n\n**Pasos generales**:\n1. Tener el proyecto en un repositorio de Git (GitHub, GitLab)\n2. Hacer build: `npm run build` → genera carpeta `dist/`\n3. Subir `dist/` a Netlify/Vercel (arrastrar o conectar repositorio)\n\n**Netlify Drop** (método más rápido):\n```bash\nnpm run build\n# Arrastrar la carpeta dist/ a https://app.netlify.com/drop\n```\n\n**Conectar repositorio (CD continuo)**:\n1. Subir el proyecto a GitHub\n2. Ir a Netlify > Add new site > Import from Git\n3. Elegir repositorio, rama (main)\n4. Build command: `npm run build`\n5. Publish directory: `dist`\n6. Cada push a main despliega automáticamente\n\n**Vercel**: similar a Netlify, detecta automáticamente Vite:\n```bash\nnpx vercel    # CLI interactivo\nnpx vercel --prod  # Desplegar a producción\n```\n\n**Buenas prácticas**:\n- Siempre ejecuta `npm run build` localmente antes de subir\n- Verifica con `npm run preview` que todo funciona\n- Usa variables de entorno para claves de API\n- Configura un dominio personalizado para producción", "exercise": "Declara un objeto `configDespliegue` con: `plataforma` ('Netlify'), `buildCommand` ('npm run build'), `publishDir` ('dist'), y un método `desplegar()` que retorne 'Desplegando en ' + this.plataforma + '...'.", "solution": "let configDespliegue = {\n  plataforma: 'Netlify',\n  buildCommand: 'npm run build',\n  publishDir: 'dist',\n  desplegar() {\n    return 'Desplegando en ' + this.plataforma + '...';\n  }\n};", "tests": ["typeof configDespliegue === 'object'", "configDespliegue.plataforma === 'Netlify'", "configDespliegue.publishDir === 'dist'", "typeof configDespliegue.desplegar === 'function'", { "type": "function", "code": "configDespliegue.desplegar()", "expected": "Desplegando en Netlify..." }] },
  { "id": 43, "module": "JavaScript en el Mundo Real", "title": "Variables de entorno en frontend", "theory": "Las **variables de entorno** almacenan configuración sensible o específica del entorno (API keys, URLs). En Vite se acceden con `import.meta.env`.\n\n**Archivo .env**:\n```env\n# Archivo .env (NO subir a git)\nVITE_API_URL=https://api.ejemplo.com\nVITE_API_KEY=abc123\n```\n\n**Acceder en código**:\n```js\nconst apiUrl = import.meta.env.VITE_API_URL;\nconst apiKey = import.meta.env.VITE_API_KEY;\n```\n\n**Importante**: Solo las variables que empiezan con `VITE_` son accesibles desde el frontend. Esto es una medida de seguridad.\n\n**Archivos .env útiles**:\n| Archivo | Propósito |\n|---------|-----------|\n| `.env` | Valores por defecto (subir a git) |\n| `.env.local` | Valores locales (NO subir a git) |\n| `.env.production` | Valores para producción |\n\n**Ejemplo de configuración**:\n```js\nconst config = {\n  url: import.meta.env.VITE_API_URL || 'http://localhost:3000',\n  modo: import.meta.env.MODE  // 'development' o 'production'\n};\n\nconsole.log('Modo:', import.meta.env.MODE);\n```\n\n**Buenas prácticas**:\n- Nunca subas `.env.local` o `.env*.local` a git\n- Usa valores por defecto en el código si la variable puede no estar definida\n- Documenta las variables necesarias en un archivo `.env.example`\n- Las variables se inyectan en tiempo de build, no en tiempo de ejecución", "exercise": "Declara un objeto `config` con: `apiUrl` ('https://api.ejemplo.com'), `modo` definido como 'development', y un método `obtenerUrl()` que retorne this.apiUrl. Declara `modoActual` como 'development' y `esProduccion` comparando si modoActual === 'production'.", "solution": "let config = {\n  apiUrl: 'https://api.ejemplo.com',\n  modo: 'development',\n  obtenerUrl() {\n    return this.apiUrl;\n  }\n};\nlet modoActual = 'development';\nlet esProduccion = modoActual === 'production';", "tests": ["typeof config === 'object'", "config.apiUrl === 'https://api.ejemplo.com'", { "type": "function", "code": "config.obtenerUrl()", "expected": "https://api.ejemplo.com" }, "typeof esProduccion === 'boolean'", "esProduccion === false"] },
  { "id": 44, "module": "JavaScript en el Mundo Real", "title": "CI/CD con GitHub Actions", "theory": "**CI/CD** (Integración Continua / Despliegue Continuo) automatiza los tests y el despliegue cada vez que subes código a Git.\n\n**GitHub Actions** ejecuta workflows automáticos en eventos como `push` o `pull_request`.\n\n**Workflow básico** (`.github/workflows/deploy.yml`):\n```yaml\nname: Deploy\non:\n  push:\n    branches: [main]\n\njobs:\n  build-and-deploy:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-node@v4\n        with:\n          node-version: 20\n      - run: npm ci\n      - run: npm test\n      - run: npm run build\n      - uses: peaceiris/actions-gh-pages@v3\n        with:\n          github_token: ${{ secrets.GITHUB_TOKEN }}\n          publish_dir: ./dist\n```\n\n**Explicación paso a paso**:\n1. `on: push branches: [main]` — se activa al subir a main\n2. `checkout` — descarga el repositorio\n3. `setup-node` — instala Node.js 20\n4. `npm ci` — instala dependencias (más rápido que npm install)\n5. `npm test` — ejecuta tests (si fallan, se detiene)\n6. `npm run build` — genera la build\n7. `actions-gh-pages` — despliega `dist/` a GitHub Pages\n\n**Secretos**: Para API keys o tokens:\n- Ir a Settings > Secrets and variables > Actions\n- Añadir secretos como `API_KEY`\n- Acceder en workflow: `${{ secrets.API_KEY }}`\n\n**Buenas prácticas**:\n- Siempre ejecuta tests antes del build en CI/CD\n- Usa `npm ci` en vez de `npm install` en CI (más rápido y determinista)\n- Mantén los workflows simples: un trabajo, pasos claros\n- Los secretos nunca se muestran en los logs de Actions", "exercise": "Declara un objeto `workflow` con: `nombre` ('CI/CD'), `rama` ('main'), `pasos` (array: 'checkout', 'install', 'test', 'build', 'deploy'), y un método `ejecutar()` que retorne 'Ejecutando ' + this.nombre + ' en rama ' + this.rama + '...'.", "solution": "let workflow = {\n  nombre: 'CI/CD',\n  rama: 'main',\n  pasos: ['checkout', 'install', 'test', 'build', 'deploy'],\n  ejecutar() {\n    return 'Ejecutando ' + this.nombre + ' en rama ' + this.rama + '...';\n  }\n};", "tests": ["typeof workflow === 'object'", "workflow.nombre === 'CI/CD'", "workflow.pasos.length === 5", "typeof workflow.ejecutar === 'function'", { "type": "function", "code": "workflow.ejecutar()", "expected": "Ejecutando CI/CD en rama main..." }] },
  { "id": 45, "module": "Asincronía", "title": "Promesas encadenadas", "theory": "Las promesas en JavaScript permiten encadenar operaciones asincrónicas de forma legible mediante el método **.then()**. Cada `.then()` devuelve una nueva promesa, lo que permite secuenciar tareas.\n\n**Encadenamiento básico:**\n```js\nPromise.resolve(1)\n  .then(val => val * 2)\n  .then(val => val + 3)\n  .then(console.log); // 5\n```\n\n**Manejo de errores con .catch():**\nEl método `.catch()` captura cualquier error que ocurra en cualquier punto de la cadena:\n```js\nPromise.reject(\"Error\")\n  .then(val => val * 2)\n  .catch(err => -1); // -1\n```\n\n**Limpieza con .finally():**\n`.finally()` se ejecuta siempre, haya o no error:\n```js\nmiPromesa\n  .then(console.log)\n  .catch(console.error)\n  .finally(() => console.log(\"Terminado\"));\n```", "exercise": "Crea una función llamada `encadenar` que devuelva una cadena de promesas. La primera promesa debe resolverse con el valor 1, luego multiplicarlo por 2 con `.then()`, luego sumarle 3 con otro `.then()`, y finalmente devolver el resultado. Incluye un `.catch()` que devuelva -1 en caso de error.", "solution": "function encadenar() {\n  return Promise.resolve(1)\n    .then(val => val * 2)\n    .then(val => val + 3)\n    .catch(() => -1);\n}", "tests": ["typeof encadenar === 'function'", "typeof encadenar().then === 'function'"] },
  { "id": 46, "module": "Asincronía", "title": "Promise.all, Promise.race, Promise.allSettled", "theory": "JavaScript ofrece tres métodos estáticos para trabajar con múltiples promesas:\n\n**Promise.all()**\nEspera a que **todas** las promesas se resuelvan. Si alguna falla, rechaza inmediatamente:\n```js\nPromise.all([p1, p2, p3])\n  .then(resultados => console.log(resultados))\n  .catch(err => console.error(err));\n```\n\n**Promise.race()**\nResuelve o rechaza con la **primera** promesa que se settlee:\n```js\nPromise.race([rapida, lenta])\n  .then(val => console.log(val));\n```\n\n**Promise.allSettled()**\nEspera a que **todas** terminen sin importar si fallan. Devuelve el estado de cada una:\n```js\nPromise.allSettled([p1, p2])\n  .then(resultados => {\n    resultados.forEach(r => console.log(r.status));\n  });\n```", "exercise": "Crea una función llamada `procesarTareas` que reciba un array de promesas y utilice `Promise.all` para esperar a que todas se completen. Debe devolver \"Todas completadas\" si todas las promesas se resuelven, o \"Error en tareas\" si alguna falla.", "solution": "function procesarTareas(tareas) {\n  return Promise.all(tareas)\n    .then(() => \"Todas completadas\")\n    .catch(() => \"Error en tareas\");\n}", "tests": ["typeof procesarTareas === 'function'", "typeof procesarTareas([]).then === 'function'"] },
  { "id": 47, "module": "Asincronía", "title": "AbortController y cancelación", "theory": "**AbortController** permite cancelar operaciones asincrónicas como peticiones fetch.\n\n**Patrón básico:**\n```js\nconst controller = new AbortController();\nconst signal = controller.signal;\n\nfetch(url, { signal })\n  .then(response => response.json())\n  .catch(err => {\n    if (err.name === 'AbortError') {\n      console.log('Petición cancelada');\n    }\n  });\n\ncontroller.abort();\n```\n\n**Usos comunes:**\n- Cancelar fetch al desmontar un componente\n- Evitar condiciones de carrera\n- Timeout en peticiones\n\n**Ejemplo con timeout:**\n```js\nconst controller = new AbortController();\nsetTimeout(() => controller.abort(), 5000);\nfetch(url, { signal: controller.signal });\n```", "exercise": "Crea una función llamada `crearPeticionCancelable` que devuelva un objeto con dos propiedades: `promesa` (una Promise que se resuelve con \"Completado\" tras 3 segundos, o se rechaza con \"Cancelado\" si se aborta) y `cancelar` (una función que llama a `controller.abort()`).", "solution": "function crearPeticionCancelable() {\n  const controller = new AbortController();\n  return {\n    promesa: new Promise((resolve, reject) => {\n      const timer = setTimeout(() => resolve(\"Completado\"), 3000);\n      controller.signal.addEventListener('abort', () => {\n        clearTimeout(timer);\n        reject(\"Cancelado\");\n      });\n    }),\n    cancelar: () => controller.abort()\n  };\n}", "tests": ["typeof crearPeticionCancelable === 'function'", "typeof crearPeticionCancelable().promesa === 'object'", "typeof crearPeticionCancelable().cancelar === 'function'"] },
  { "id": 48, "module": "Programación Avanzada", "title": "Patrón Singleton", "theory": "El **patrón Singleton** garantiza que una clase tenga una única instancia y proporciona un punto de acceso global a ella.\n\n**Implementación con clase**\nSe usa un campo estático privado (`#instancia`) para almacenar la instancia única. El constructor verifica si ya existe una instancia y la retorna en lugar de crear una nueva.\n\n```js\nclass Configuracion {\n  static #instancia = null;\n\n  constructor() {\n    if (Configuracion.#instancia) {\n      return Configuracion.#instancia;\n    }\n    this.config = {};\n    Configuracion.#instancia = this;\n  }\n\n  get(key) {\n    return this.config[key];\n  }\n\n  set(key, value) {\n    this.config[key] = value;\n  }\n}\n```\n\n**Implementación con módulo**\nTambién se puede lograr con un objeto literal exportado como módulo:\n\n```js\nconst config = {\n  valores: {},\n  get(key) { return this.valores[key]; },\n  set(key, value) { this.valores[key] = value; }\n};\nexport default config;\n```\n\n**Casos de uso**\n- Configuración global de la aplicación\n- Logger compartido\n- Conexión a base de datos\n- Cache unificado", "exercise": "Crea una `class Configuracion` que implemente el patrón Singleton. El constructor debe verificar si ya existe una instancia y retornarla en ese caso. Agrega los métodos `get(key)` y `set(key, value)` que lean y escriban desde un objeto interno `this.config`.", "solution": "class Configuracion {\n  static #instancia = null;\n\n  constructor() {\n    if (Configuracion.#instancia) {\n      return Configuracion.#instancia;\n    }\n    this.config = {};\n    Configuracion.#instancia = this;\n  }\n\n  get(key) {\n    return this.config[key];\n  }\n\n  set(key, value) {\n    this.config[key] = value;\n  }\n}", "tests": ["typeof Configuracion === 'function'", { "type": "function", "code": "(() => { const a = new Configuracion(); const b = new Configuracion(); return a === b; })()", "expected": true }, { "type": "function", "code": "(() => { const c = new Configuracion(); c.set('tema', 'oscuro'); return c.get('tema'); })()", "expected": "oscuro" }] },
  { "id": 49, "module": "Programación Avanzada", "title": "Patrón Observer", "theory": "El **patrón Observer** (o Pub/Sub) permite que objetos se suscriban a eventos y sean notificados cuando ocurren. Es ideal para comunicación desacoplada entre componentes.\n\n**Estructura básica**\nUn `EventEmitter` mantiene un diccionario de eventos, donde cada evento tiene un array de callbacks suscriptos.\n\n```js\nclass EventEmitter {\n  constructor() {\n    this.eventos = {};\n  }\n\n  on(evento, callback) {\n    if (!this.eventos[evento]) {\n      this.eventos[evento] = [];\n    }\n    this.eventos[evento].push(callback);\n  }\n\n  emit(evento, ...args) {\n    const callbacks = this.eventos[evento];\n    if (callbacks) {\n      callbacks.forEach(cb => cb(...args));\n    }\n  }\n\n  off(evento, callback) {\n    const callbacks = this.eventos[evento];\n    if (callbacks) {\n      this.eventos[evento] = callbacks.filter(cb => cb !== callback);\n    }\n  }\n}\n```\n\n**Uso**\n```js\nconst emisor = new EventEmitter();\n\nfunction alHacerClick(nombre) {\n  console.log(`Click de ${nombre}`);\n}\n\nemisor.on('click', alHacerClick);\nemisor.emit('click', 'Usuario');\nemisor.off('click', alHacerClick);\n```\n\nMúltiples suscriptores pueden escuchar el mismo evento y se ejecutarán en orden de registro.", "exercise": "Crea una `class EventEmitter` con:\n- `on(evento, callback)`: almacena el callback en un array dentro de `this.eventos[evento]`\n- `emit(evento, ...args)`: ejecuta todos los callbacks del evento con los argumentos\n- `off(evento, callback)`: elimina un callback específico del array", "solution": "class EventEmitter {\n  constructor() {\n    this.eventos = {};\n  }\n\n  on(evento, callback) {\n    if (!this.eventos[evento]) {\n      this.eventos[evento] = [];\n    }\n    this.eventos[evento].push(callback);\n  }\n\n  emit(evento, ...args) {\n    const callbacks = this.eventos[evento];\n    if (callbacks) {\n      callbacks.forEach(cb => cb(...args));\n    }\n  }\n\n  off(evento, callback) {\n    const callbacks = this.eventos[evento];\n    if (callbacks) {\n      this.eventos[evento] = callbacks.filter(cb => cb !== callback);\n    }\n  }\n}", "tests": ["typeof EventEmitter === 'function'", "const em = new EventEmitter(); typeof em.on === 'function'", "const em = new EventEmitter(); typeof em.emit === 'function'", "const em = new EventEmitter(); typeof em.off === 'function'", { "type": "function", "code": "(() => { const em = new EventEmitter(); let r = ''; em.on('saludo', (n) => { r = n; }); em.emit('saludo', 'hola'); return r; })()", "expected": "hola" }] },
  { "id": 50, "module": "Programación Avanzada", "title": "Patrón Factory", "theory": "El **patrón Factory** es un patrón de creación que encapsula la lógica de creación de objetos sin exponer la clase concreta al cliente.\n\n**Idea principal**\nEn lugar de usar `new` directamente, llamamos a una función factory que decide qué objeto crear según un parámetro.\n\n**Ejemplo: fábrica de figuras**\n```js\nfunction crearFigura(tipo) {\n  if (tipo === 'circulo') {\n    return {\n      tipo: 'circulo',\n      area(radio) {\n        return Math.PI * radio ** 2;\n      }\n    };\n  }\n  if (tipo === 'rectangulo') {\n    return {\n      tipo: 'rectangulo',\n      area(base, altura) {\n        return base * altura;\n      }\n    };\n  }\n  return null;\n}\n```\n\n**Uso**\n```js\nconst c = crearFigura('circulo');\nc.area(5); // 78.54\n\nconst r = crearFigura('rectangulo');\nr.area(4, 6); // 24\n\nconst x = crearFigura('triangulo'); // null\n```\n\n**Ventajas**\n- Centraliza la lógica de creación\n- Oculta la complejidad de instanciación\n- Fácil de extender con nuevos tipos", "exercise": "Crea una función `crearFigura(tipo)` que retorne:\n- `'circulo'` → `{ tipo: 'circulo', area(radio) { return Math.PI * radio ** 2 } }`\n- `'rectangulo'` → `{ tipo: 'rectangulo', area(base, altura) { return base * altura } }`\n- cualquier otro valor → `null`", "solution": "function crearFigura(tipo) {\n  if (tipo === 'circulo') {\n    return {\n      tipo: 'circulo',\n      area(radio) {\n        return Math.PI * radio ** 2;\n      }\n    };\n  }\n  if (tipo === 'rectangulo') {\n    return {\n      tipo: 'rectangulo',\n      area(base, altura) {\n        return base * altura;\n      }\n    };\n  }\n  return null;\n}", "tests": ["typeof crearFigura === 'function'", { "type": "function", "code": "crearFigura('circulo').tipo", "expected": "circulo" }, { "type": "function", "code": "crearFigura('rectangulo').tipo", "expected": "rectangulo" }, { "type": "function", "code": "crearFigura('desconocido')", "expected": null }, { "type": "expression", "code": "Math.abs(crearFigura('circulo').area(5) - 78.53981633974483) < 0.0001" }] },
  { "id": 51, "module": "Fundamentos del Lenguaje", "title": "Ficha personal interactiva", "theory": "Los **objetos** agrupan datos relacionados en pares clave:valor. Combinados con **template literals** y **métodos**, permiten crear estructuras de datos autocontenidas.\n\n```js\nconst persona = {\n  nombre: 'Ana',\n  edad: 30,\n  pais: 'Colombia',\n  hobbies: ['leer', 'correr'],\n  mostrar() {\n    return `${this.nombre} (${this.edad}), ${this.pais} — Pasatiempos: ${this.hobbies.join(', ')}`;\n  }\n};\n\nconsole.log(persona.mostrar());\n```\n\n**Propiedades**: son variables dentro del objeto. Se acceden con `objeto.propiedad`.\n\n**Métodos**: son funciones dentro del objeto. Usan `this` para referirse al propio objeto.\n\n**Template literals** (`` ` ``) permiten interpolar variables y expresiones:\n```js\n`${nombre} (${edad})`\n```\n\n**`this`** dentro de un método apunta al objeto que lo contiene. Sin `this`, la variable buscaría en el ámbito exterior.\n\n**Buenas prácticas**: Usa objetos para agrupar datos relacionados. Nombra los métodos como verbos (`mostrar`, `calcular`, `obtener`). Prefiere template literals sobre concatenación con `+`.", "exercise": "Crea un objeto `ficha` con las propiedades: `nombre` (string), `edad` (number), `pais` (string), `hobbies` (array de strings) y un método `mostrar()` que retorne un string usando template literals con el formato: `'[nombre] ([edad]), [pais] — Pasatiempos: [hobbie1], [hobbie2]'`. Usa `this.hobbies.join(', ')` para los pasatiempos.", "solution": "const ficha = {\n  nombre: 'Carlos',\n  edad: 25,\n  pais: 'México',\n  hobbies: ['leer', 'programar', 'música'],\n  mostrar() {\n    return `${this.nombre} (${this.edad}), ${this.pais} — Pasatiempos: ${this.hobbies.join(', ')}`;\n  }\n};", "tests": ["typeof ficha === 'object'", "typeof ficha.nombre === 'string'", "typeof ficha.mostrar === 'function'", { "type": "expression", "code": "ficha.mostrar().length >= 20" }] },
  { "id": 52, "module": "Control de Flujo", "title": "Juego del número secreto", "theory": "Las **condicionales** (`if/else if/else`) permiten tomar decisiones según el valor de una expresión. Combinadas con **`Math.random()`** crean juegos interactivos.\n\n```js\nconst numeroSecreto = Math.floor(Math.random() * 100) + 1;\n\nfunction adivinar(intento) {\n  if (intento < numeroSecreto) {\n    return 'menor';\n  } else if (intento > numeroSecreto) {\n    return 'mayor';\n  } else {\n    return 'acertaste';\n  }\n}\n```\n\n**`Math.random()`** devuelve un decimal entre 0 (incluido) y 1 (excluido).\n\n**`Math.floor()`** redondea hacia abajo.\n\n**Fórmula para rango**: `Math.floor(Math.random() * (max - min + 1)) + min`\n\nPara `min=1, max=100`: `Math.floor(Math.random() * 100) + 1` → números del 1 al 100.\n\n**Estructura if/else if/else**:\n```js\nif (condicion1) {\n  // se ejecuta si condicion1 es true\n} else if (condicion2) {\n  // se ejecuta si condicion1 es false y condicion2 es true\n} else {\n  // se ejecuta si todas las anteriores son false\n}\n```\n\n**Buenas prácticas**: Ordena las condiciones de la más específica a la más general. Usa `return` temprano para evitar anidamiento excesivo.", "exercise": "Crea una función `jugarNumeroSecreto(intento)` que: genere `numeroSecreto` con `Math.floor(Math.random()*100)+1` **dentro de la función cada vez que se llama**, y retorne `'menor'` si intento < numeroSecreto, `'mayor'` si intento > numeroSecreto, `'acertaste'` si son iguales. Luego llama a la función con argumento 50 y guarda el resultado en la variable `resultado`.", "solution": "function jugarNumeroSecreto(intento) {\n  const numeroSecreto = Math.floor(Math.random() * 100) + 1;\n  if (intento < numeroSecreto) {\n    return 'menor';\n  } else if (intento > numeroSecreto) {\n    return 'mayor';\n  } else {\n    return 'acertaste';\n  }\n}\nconst resultado = jugarNumeroSecreto(50);", "tests": ["typeof jugarNumeroSecreto === 'function'", "['menor', 'mayor', 'acertaste'].includes(resultado)"] },
  { "id": 53, "module": "Funciones", "title": "Generador de contraseñas", "theory": "Las **funciones** pueden llamarse entre sí para dividir un problema en partes pequeñas. Esta técnica se llama **composición de funciones**.\n\n```js\nfunction caracterAleatorio() {\n  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';\n  const indice = Math.floor(Math.random() * chars.length);\n  return chars[indice];\n}\n\nfunction generarPassword(longitud = 8) {\n  let password = '';\n  for (let i = 0; i < longitud; i++) {\n    password += caracterAleatorio();\n  }\n  return password;\n}\n\nconsole.log(generarPassword());     // 'aB3xK9mQ'\nconsole.log(generarPassword(12));   // 'F7gH2jL9pQ4w'\n```\n\n**Parámetros por defecto**: `longitud = 8` asigna 8 si no se proporciona argumento.\n\n**Acceso por índice**: `chars[indice]` obtiene el carácter en la posición `indice`.\n\n**Buena práctica**: Divide la lógica en funciones pequeñas — `caracterAleatorio` tiene una sola responsabilidad (generar un carácter aleatorio), y `generarPassword` se enfoca en construir la cadena.\n\n**Composición**: `generarPassword` delega la generación del carácter a `caracterAleatorio`, haciendo el código más legible y reutilizable.", "exercise": "Crea una función `caracterAleatorio()` que retorne un carácter aleatorio del charset `'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789'`. Luego crea una función `generarPassword(longitud = 8)` que genere y retorne una contraseña de la longitud indicada usando `caracterAleatorio()` dentro de un bucle `for`.", "solution": "function caracterAleatorio() {\n  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';\n  return chars[Math.floor(Math.random() * chars.length)];\n}\n\nfunction generarPassword(longitud = 8) {\n  let password = '';\n  for (let i = 0; i < longitud; i++) {\n    password += caracterAleatorio();\n  }\n  return password;\n}", "tests": ["typeof generarPassword === 'function'", { "type": "function", "code": "generarPassword().length", "expected": 8 }, { "type": "function", "code": "generarPassword(12).length", "expected": 12 }, { "type": "expression", "code": "typeof generarPassword() === 'string'" }] },
  { "id": 54, "module": "Arrays y Objetos", "title": "Gestor de tareas", "theory": "Las operaciones **CRUD** (Create, Read, Update, Delete) sobre arrays de objetos son la base de muchas aplicaciones. En JavaScript se implementan con métodos inmutables como `map`, `filter`, `findIndex` y el **spread operator**.\n\n```js\nlet tareas = [\n  { id: 1, texto: 'Aprender JS', completada: false },\n  { id: 2, texto: 'Hacer ejercicio', completada: true }\n];\n\nfunction agregarTarea(tareas, texto) {\n  const nueva = { id: Date.now(), texto, completada: false };\n  return [...tareas, nueva];\n}\n\nfunction completarTarea(tareas, id) {\n  return tareas.map(t =>\n    t.id === id ? { ...t, completada: true } : t\n  );\n}\n\nfunction tareasPendientes(tareas) {\n  return tareas.filter(t => !t.completada);\n}\n```\n\n**Inmutabilidad**: en lugar de modificar el array original, cada función retorna un **nuevo array**. Esto evita efectos secundarios y facilita la depuración.\n\n**Spread `...`**: `[...tareas, nuevo]` crea un nuevo array copiando los elementos existentes y añadiendo uno nuevo.\n\n**`map()`**: transforma cada elemento. Si el id coincide, reemplaza la tarea con `{ ...t, completada: true }`; si no, la deja igual.\n\n**`filter()`**: selecciona elementos que cumplan la condición (`!t.completada` → no completadas).\n\n**Buenas prácticas**: Nunca mutes el estado directamente. Cada operación CRUD debe retornar un nuevo array.", "exercise": "Crea tres funciones para un gestor de tareas: `agregarTarea(tareas, texto)` — retorna un nuevo array con la tarea agregada (objeto con `id`, `texto`, `completada: false`); `completarTarea(tareas, id)` — retorna un nuevo array con la tarea cuyo id coincida marcada como `completada: true` (usa map); `tareasPendientes(tareas)` — retorna solo las tareas no completadas (usa filter).", "solution": "function agregarTarea(tareas, texto) {\n  return [...tareas, { id: Date.now(), texto, completada: false }];\n}\n\nfunction completarTarea(tareas, id) {\n  return tareas.map(t =>\n    t.id === id ? { ...t, completada: true } : t\n  );\n}\n\nfunction tareasPendientes(tareas) {\n  return tareas.filter(t => !t.completada);\n}", "tests": ["typeof agregarTarea === 'function'", "typeof completarTarea === 'function'", "typeof tareasPendientes === 'function'"] },
  { "id": 55, "module": "DOM y Eventos", "title": "Mini-app de notas con persistencia", "theory": "En esta lección aprenderás a crear, agregar y eliminar elementos del DOM usando **createElement**, **appendChild** y **remove**. Construiremos una mini-app de notas donde cada nota es un elemento `div` con un párrafo y un botón para eliminarla.\n\nTambién veremos el patrón de **persistencia con localStorage**:\n\n```js\nlocalStorage.setItem('notas', JSON.stringify(misNotas));\nconst notas = JSON.parse(localStorage.getItem('notas'));\n```\n\n**JSON.stringify** convierte un array/objeto a string JSON. **JSON.parse** hace la operación inversa. Este patrón permite mantener datos entre sesiones del navegador.", "exercise": "Crea las siguientes funciones:\n- `crearNota(texto)` — retorna un elemento `<div class=\"nota\"><p>texto</p><button>Eliminar</button></div>` usando createElement y textContent.\n- `guardarNotas(notas)` — guarda el array de notas en localStorage bajo la clave 'notas' usando JSON.stringify.\n- `cargarNotas()` — lee y parsea desde localStorage; si no hay datos o hay error, retorna `[]`.", "solution": "function crearNota(texto) {\n  const div = document.createElement('div');\n  div.className = 'nota';\n  const p = document.createElement('p');\n  p.textContent = texto;\n  const btn = document.createElement('button');\n  btn.textContent = 'Eliminar';\n  div.appendChild(p);\n  div.appendChild(btn);\n  return div;\n}\n\nfunction guardarNotas(notas) {\n  localStorage.setItem('notas', JSON.stringify(notas));\n}\n\nfunction cargarNotas() {\n  try {\n    const data = localStorage.getItem('notas');\n    return data ? JSON.parse(data) : [];\n  } catch {\n    return [];\n  }\n}", "tests": ["typeof crearNota === 'function'", "typeof guardarNotas === 'function'", "typeof cargarNotas === 'function'"] },
  { "id": 56, "module": "Asincronía", "title": "Buscador de películas con API", "theory": "Las APIs web se consumen con **fetch** y la sintaxis **async/await**. Permite escribir código asíncrono que se lee como si fuera síncrono.\n\n```js\nasync function buscarDatos(url) {\n  const respuesta = await fetch(url);\n  const datos = await respuesta.json();\n  return datos;\n}\n```\n\nPara simular una API usaremos **setTimeout** dentro de una Promise, el mecanismo base de toda operación asíncrona. El filtrado se hace con **filter** e **includes** para búsqueda case-insensitive.", "exercise": "Crea una función asíncrona `buscarPeliculas(termino)` que:\n- Espere 100ms usando setTimeout envuelto en una Promise.\n- Retorne resultados mock: `[{titulo:'El Padrino', anio:1972, genero:'Drama'}, {titulo:'Inception', anio:2010, genero:'Ciencia Ficcion'}, {titulo:'Matrix', anio:1999, genero:'Ciencia Ficcion'}]`.\n- Filtre por término (case-insensitive includes en titulo).\n- Si no hay resultados, retorne 'Sin resultados'.\n- Use async/await.", "solution": "const peliculas = [\n  { titulo: 'El Padrino', anio: 1972, genero: 'Drama' },\n  { titulo: 'Inception', anio: 2010, genero: 'Ciencia Ficcion' },\n  { titulo: 'Matrix', anio: 1999, genero: 'Ciencia Ficcion' }\n];\n\nasync function buscarPeliculas(termino) {\n  await new Promise(resolve => setTimeout(resolve, 100));\n  const filtradas = peliculas.filter(p =>\n    p.titulo.toLowerCase().includes(termino.toLowerCase())\n  );\n  return filtradas.length > 0 ? filtradas : 'Sin resultados';\n}", "tests": ["typeof buscarPeliculas === 'function'", "typeof buscarPeliculas('test').then === 'function'"] },
  { "id": 57, "module": "Programación Avanzada", "title": "Simulador de tienda con Observer", "theory": "El **patrón Observer** permite que objetos se suscriban a eventos y reaccionen cuando ocurren. Es ideal para desacoplar componentes: el carrito emite eventos y la interfaz se actualiza sin conocer los detalles internos.\n\n```js\nclass EventEmitter {\n  constructor() { this.eventos = {}; }\n  on(e, cb) { if (!this.eventos[e]) this.eventos[e] = []; this.eventos[e].push(cb); }\n  emit(e, ...args) { const cbs = this.eventos[e]; if (cbs) cbs.forEach(cb => cb(...args)); }\n  off(e, cb) { if (!this.eventos[e]) return; this.eventos[e] = this.eventos[e].filter(f => f !== cb); }\n}\n```\n\nEste patrón desacopla los componentes: el carrito emite 'actualizar' y la UI responde automáticamente.", "exercise": "Crea una clase `EventEmitter` con `on`, `emit`, `off`. Luego crea una clase `CarritoObserver` que contenga un EventEmitter interno y tenga: `items = []`, `agregarProducto(producto)` (agrega y emite 'actualizar'), `quitarProducto(id)` (elimina por id y emite), `obtenerItems()` (retorna items), `total()` (suma de precios con reduce).", "solution": "class EventEmitter {\n  constructor() { this.eventos = {}; }\n  on(evento, callback) { if (!this.eventos[evento]) this.eventos[evento] = []; this.eventos[evento].push(callback); }\n  emit(evento, ...args) { const cbs = this.eventos[evento]; if (cbs) cbs.forEach(cb => cb(...args)); }\n  off(evento, callback) { if (!this.eventos[evento]) return; this.eventos[evento] = this.eventos[evento].filter(cb => cb !== callback); }\n}\n\nclass CarritoObserver {\n  constructor() { this.items = []; this.emitter = new EventEmitter(); }\n  agregarProducto(producto) { this.items.push(producto); this.emitter.emit('actualizar'); }\n  quitarProducto(id) { this.items = this.items.filter(p => p.id !== id); this.emitter.emit('actualizar'); }\n  obtenerItems() { return this.items; }\n  total() { return this.items.reduce((sum, p) => sum + p.precio, 0); }\n}", "tests": ["typeof CarritoObserver === 'function'", "typeof EventEmitter === 'function'"] },
  { "id": 58, "module": "Optimización y Buenas Prácticas", "title": "Analizador de rendimiento de arrays", "theory": "Diferentes métodos de array tienen distinto rendimiento. Compararemos **for clásico**, **forEach**, **map**, **filter** y **reduce**.\n\n```js\nconsole.time('medicion');\nfor (let i = 0; i < arr.length; i++) { suma += arr[i]; }\nconsole.timeEnd('medicion');\n```\n\n**Notación Big O**:\n- `O(1)` — acceso por índice\n- `O(n)` — recorrido lineal (for, forEach, filter, map, reduce)\n- `O(n²)` — bucles anidados\n\n**console.time** y **console.timeEnd** permiten medir duración de operaciones para tomar decisiones informadas.", "exercise": "Crea las siguientes funciones:\n- `medirTiempo(fn, arr)` — ejecuta fn(arr) envuelto en console.time/console.timeEnd('medicion'), retorna el resultado.\n- `sumaFor(arr)` — suma elementos con bucle for clásico.\n- `sumaReduce(arr)` — suma elementos con reduce.\n- `filtrarYTransformar(arr)` — filtra números pares mayores a 10 y los duplica con map.", "solution": "function medirTiempo(fn, arr) {\n  console.time('medicion');\n  const resultado = fn(arr);\n  console.timeEnd('medicion');\n  return resultado;\n}\n\nfunction sumaFor(arr) {\n  let suma = 0;\n  for (let i = 0; i < arr.length; i++) {\n    suma += arr[i];\n  }\n  return suma;\n}\n\nfunction sumaReduce(arr) {\n  return arr.reduce((acc, n) => acc + n, 0);\n}\n\nfunction filtrarYTransformar(arr) {\n  return arr.filter(n => n % 2 === 0 && n > 10).map(n => n * 2);\n}", "tests": ["typeof medirTiempo === 'function'", "typeof sumaFor === 'function'", "typeof sumaReduce === 'function'", "typeof filtrarYTransformar === 'function'"] },
  { "id": 59, "module": "DOM y Eventos", "title": "Delegación de eventos", "theory": "La **delegación de eventos** aprovecha el burbujeo (bubbling) para manejar eventos en múltiples elementos con un solo listener.\n\nCuando un evento ocurre, viaja desde `event.target` (elemento que disparó el evento) hasta `event.currentTarget` (elemento donde está el listener).\n\n```js\ndocument.querySelector('ul').addEventListener('click', function(e) {\n  if (e.target.tagName === 'LI') {\n    console.log('Hiciste click en:', e.target.textContent);\n  }\n});\n```\n\n- `event.target`: elemento que originó el evento\n- `event.currentTarget`: elemento que tiene el listener\n- `event.bubbles`: booleano, indica si el evento burbujea\n- `event.stopPropagation()`: detiene el burbujeo", "exercise": "Escribe una función `manejarClick(e)` que reciba un evento de click y retorne el `textContent` del elemento `<li>` que fue clickeado (event.target).", "solution": "function manejarClick(e) {\n  return e.target.textContent;\n}", "tests": ["typeof manejarClick === 'function'", { "type": "function", "code": "manejarClick({target:{textContent:'Hola'}})", "expected": "Hola" }, { "type": "function", "code": "manejarClick({target:{textContent:'Mundo'}})", "expected": "Mundo" }] },
  { "id": 60, "module": "DOM y Eventos", "title": "IntersectionObserver", "theory": "`IntersectionObserver` permite detectar cuándo un elemento entra o sale del viewport, ideal para **lazy loading** de imágenes o **scroll infinito**.\n\n```js\nconst observer = new IntersectionObserver((entries) => {\n  entries.forEach(entry => {\n    if (entry.isIntersecting) {\n      console.log('Elemento visible:', entry.target);\n    }\n  });\n}, { threshold: 0.5 });\n\nobserver.observe(document.querySelector('.lazy'));\n```\n\n- `threshold`: porcentaje de visibilidad (0-1)\n- `rootMargin`: margen extra alrededor del viewport\n- Llama a `observe(elemento)` para empezar a vigilar", "exercise": "Escribe una función `crearObserver(callback)` que cree y retorne un `IntersectionObserver` que ejecute `callback` cuando un elemento sea intersectado (con threshold 0.5).", "solution": "function crearObserver(callback) {\n  return new IntersectionObserver(callback, { threshold: 0.5 });\n}", "tests": ["typeof crearObserver === 'function'", { "type": "function", "code": "const obs = crearObserver(()=>{}); obs instanceof IntersectionObserver", "expected": true }, { "type": "function", "code": "const obs = crearObserver(()=>{}); typeof obs.observe === 'function'", "expected": true }] },
  { "id": 61, "module": "DOM y Eventos", "title": "IndexedDB básico", "theory": "**IndexedDB** es una base de datos NoSQL en el navegador para almacenar objetos estructurados.\n\n```js\nconst request = indexedDB.open('MiDB', 1);\n\nrequest.onupgradeneeded = (e) => {\n  const db = e.target.result;\n  const store = db.createObjectStore('items', { keyPath: 'id' });\n};\n\nrequest.onsuccess = (e) => {\n  const db = e.target.result;\n};\n```\n\n**CRUD básico:**\n- `store.put(datos)` — crear o actualizar\n- `store.get(id)` — leer\n- `store.delete(id)` — eliminar\n- `store.getAll()` — obtener todos\n\nLas operaciones se envuelven en transacciones: `db.transaction('items', 'readwrite').objectStore('items')`", "exercise": "Escribe tres funciones:\n1. `abrirDB()` — retorna una Promise que resuelve con la base de datos `'MiDB'` (versión 1)\n2. `agregarRegistro(db, datos)` — agrega un registro al object store `'items'`\n3. `obtenerRegistros(db)` — retorna una Promise con todos los registros del store `'items'`", "solution": "function abrirDB() {\n  return new Promise((resolve, reject) => {\n    const request = indexedDB.open('MiDB', 1);\n    request.onupgradeneeded = () => request.result.createObjectStore('items', { keyPath: 'id' });\n    request.onsuccess = () => resolve(request.result);\n    request.onerror = () => reject(request.error);\n  });\n}\nfunction agregarRegistro(db, datos) {\n  return new Promise((resolve, reject) => {\n    const tx = db.transaction('items', 'readwrite');\n    const store = tx.objectStore('items');\n    store.put(datos);\n    tx.oncomplete = () => resolve();\n    tx.onerror = () => reject(tx.error);\n  });\n}\nfunction obtenerRegistros(db) {\n  return new Promise((resolve, reject) => {\n    const tx = db.transaction('items', 'readonly');\n    const store = tx.objectStore('items');\n    const request = store.getAll();\n    request.onsuccess = () => resolve(request.result);\n    request.onerror = () => reject(request.error);\n  });\n}", "tests": ["typeof abrirDB === 'function'", "typeof agregarRegistro === 'function'", "typeof obtenerRegistros === 'function'"] },
  { "id": 62, "module": "DOM y Eventos", "title": "History API", "theory": "La **History API** permite manipular el historial del navegador sin recargar la página, esencial para **SPA**.\n\n```js\n// Añadir entrada al historial\nhistory.pushState({ page: 1 }, 'Título', '/pagina1');\n\n// Reemplazar entrada actual\nhistory.replaceState({ page: 2 }, 'Título', '/pagina2');\n\n// Escuchar cambios\nwindow.addEventListener('popstate', (e) => {\n  console.log('Navegaste a:', e.state);\n});\n```\n\n- `pushState(state, title, url)`: añade nueva entrada\n- `replaceState(state, title, url)`: reemplaza la actual\n- `popstate`: evento al navegar atrás/adelante", "exercise": "Escribe una función `navegar(ruta)` que llame a `history.pushState` con `{ ruta }` como state, título vacío, y la ruta como URL; luego retorne la ruta.", "solution": "function navegar(ruta) {\n  history.pushState({ ruta }, '', ruta);\n  return ruta;\n}", "tests": ["typeof navegar === 'function'", { "type": "function", "code": "navegar('/inicio')", "expected": "/inicio" }] },
  { "id": 63, "module": "DOM y Eventos", "title": "Drag & Drop API", "theory": "La **Drag & Drop API** permite arrastrar elementos nativamente.\n\n```js\nconst elemento = document.querySelector('.drag');\nelemento.draggable = true;\n\nelemento.addEventListener('dragstart', (e) => {\n  e.dataTransfer.setData('text/plain', elemento.id);\n});\n\ndocument.addEventListener('dragover', (e) => e.preventDefault());\n\ndocument.addEventListener('drop', (e) => {\n  e.preventDefault();\n  const id = e.dataTransfer.getData('text/plain');\n  console.log('Soltaste:', id);\n});\n```\n\n- `dragstart`: comienza el arrastre, guarda datos en `dataTransfer`\n- `dragover`: necesario llamar a `preventDefault()` para permitir soltar\n- `drop`: se ejecuta al soltar el elemento", "exercise": "Escribe una función `configurarDrag(elemento)` que:\n1. Establezca `elemento.draggable = true`\n2. Agregue un listener `dragstart` que guarde el `id` del elemento en `dataTransfer`\n3. Retorne el elemento", "solution": "function configurarDrag(elemento) {\n  elemento.draggable = true;\n  elemento.addEventListener('dragstart', (e) => {\n    e.dataTransfer.setData('text/plain', elemento.id);\n  });\n  return elemento;\n}", "tests": ["typeof configurarDrag === 'function'", { "type": "function", "code": "const el = {id:'test',draggable:false,addEventListener:()=>{}}; configurarDrag(el); el.draggable", "expected": true }] },
  { "id": 64, "module": "DOM y Eventos", "title": "Clipboard API", "theory": "La **Clipboard API** permite leer y escribir en el portapapeles del sistema de forma asíncrona.\n\n```js\n// Escribir en el portapapeles\nawait navigator.clipboard.writeText('Texto a copiar');\n\n// Leer del portapapeles\nconst texto = await navigator.clipboard.readText();\n\n// Verificar permisos\nconst estado = await navigator.permissions.query({ name: 'clipboard-write' });\nif (estado.state === 'granted') {\n  console.log('Permiso concedido');\n}\n```\n\nRequiere contexto seguro (HTTPS o localhost) y permiso del usuario.\n\n- `writeText(texto)`: copia texto al portapapeles\n- `readText()`: pega texto desde el portapapeles\n- `permissions.query()`: consulta estado de permisos", "exercise": "Escribe una función async `copiarTexto(texto)` que use `navigator.clipboard.writeText` para copiar el texto al portapapeles y retorne el mismo texto.", "solution": "async function copiarTexto(texto) {\n  await navigator.clipboard.writeText(texto);\n  return texto;\n}", "tests": ["typeof copiarTexto === 'function'", { "type": "function", "code": "copiarTexto('hola') instanceof Promise", "expected": true }] },
  { "id": 65, "module": "DOM y Eventos", "title": "Geolocation API", "theory": "La **Geolocation API** obtiene la ubicación geográfica del dispositivo.\n\n```js\nnavigator.geolocation.getCurrentPosition(\n  (pos) => {\n    console.log('Latitud:', pos.coords.latitude);\n    console.log('Longitud:', pos.coords.longitude);\n  },\n  (err) => {\n    console.error('Error:', err.message);\n  },\n  { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }\n);\n```\n\nOpciones:\n- `enableHighAccuracy`: usa GPS si está disponible\n- `timeout`: tiempo máximo de espera (ms)\n- `maximumAge`: caché de posición (ms)\n\nEl error puede ser `PERMISSION_DENIED`, `POSITION_UNAVAILABLE` o `TIMEOUT`.", "exercise": "Escribe una función `obtenerPosicion()` que retorne una Promise que resuelva con un objeto `{ lat, lng }` usando `navigator.geolocation.getCurrentPosition`.", "solution": "function obtenerPosicion() {\n  return new Promise((resolve, reject) => {\n    navigator.geolocation.getCurrentPosition(\n      (pos) => resolve({ lat: pos.coords.latitude, lng: pos.coords.longitude }),\n      (err) => reject(err)\n    );\n  });\n}", "tests": ["typeof obtenerPosicion === 'function'", { "type": "function", "code": "obtenerPosicion() instanceof Promise", "expected": true }] },
  { "id": 66, "module": "Asincronía", "title": "Callbacks y callback hell", "theory": "Las **callbacks** son funciones que se pasan como argumento a otra función para ejecutarse después. El **callback hell** ocurre cuando anidamos muchas callbacks, creando una pirámide que dificulta la lectura.\n\n```js\nfunction paso1(cb) {\n  setTimeout(() => cb('paso 1'), 1000);\n}\nfunction paso2(cb) {\n  setTimeout(() => cb('paso 2'), 1000);\n}\n// Callback hell\npaso1((res) => {\n  paso2((res2) => {\n    console.log(res, res2);\n  });\n});\n```\n\nLas Promesas ayudan a aplanar esta pirámide.", "exercise": "Crea la función `cargarDatos(callback)` que ejecute `callback('datos')` después de 100ms usando `setTimeout`.", "solution": "function cargarDatos(callback) {\n  setTimeout(() => callback('datos'), 100);\n}", "tests": ["typeof cargarDatos === 'function'", "cargarDatos.length === 1", "(() => { let flag = false; const cb = () => { flag = true; }; try { cargarDatos(cb); return true; } catch(e) { return false; } })()"] },
  { "id": 67, "module": "Asincronía", "title": "Fetch API y APIs reales", "theory": "La **Fetch API** permite hacer peticiones HTTP con `fetch(url)`. Devuelve una Promesa que resuelve en un objeto `Response`. Usamos `.json()` para extraer el cuerpo como objeto.\n\n```js\nasync function obtenerUsuario(id) {\n  const res = await fetch(`https://api.example.com/users/${id}`);\n  if (!res.ok) throw new Error('Error HTTP: ' + res.status);\n  return res.json();\n}\n```\n\nSiempre verifica `response.ok` antes de procesar los datos.", "exercise": "Crea la función asíncrona `obtenerUsuario(id)` que retorne una Promesa que resuelve en `{ id: 1, nombre: 'Ana' }`.", "solution": "async function obtenerUsuario(id) {\n  return { id, nombre: 'Ana' };\n}", "tests": ["typeof obtenerUsuario === 'function'", "typeof obtenerUsuario(1).then === 'function'", "obtenerUsuario.length === 1"] },
  { "id": 68, "module": "Asincronía", "title": "Reintentos con exponential backoff", "theory": "El **exponential backoff** consiste en esperar tiempos crecientes entre reintentos: 1s, 2s, 4s, 8s... Esto evita saturar un servidor caído.\n\n```js\nasync function fetchConReintento(url, intentos = 3) {\n  for (let i = 0; i < intentos; i++) {\n    try {\n      return await fetch(url);\n    } catch (err) {\n      if (i === intentos - 1) throw err;\n      await new Promise(r => setTimeout(r, 1000 * Math.pow(2, i)));\n    }\n  }\n}\n```\n\nLa espera exponencial da tiempo al servidor para recuperarse.", "exercise": "Crea la función asíncrona `fetchConReintento(url, intentos = 3)` que retorne una Promesa.", "solution": "async function fetchConReintento(url, intentos = 3) {\n  for (let i = 0; i < intentos; i++) {\n    try {\n      return await Promise.resolve(url);\n    } catch (err) {\n      if (i === intentos - 1) throw err;\n      await new Promise(r => setTimeout(r, 100));\n    }\n  }\n}", "tests": ["typeof fetchConReintento === 'function'", "fetchConReintento.length === 2 || fetchConReintento.length === 1", "typeof fetchConReintento('test').then === 'function'"] },
  { "id": 69, "module": "Asincronía", "title": "API paginada", "theory": "Las **APIs paginadas** devuelven resultados en páginas. Leemos página por página hasta recibir un array vacío.\n\n```js\nasync function obtenerTodos(urlBase) {\n  let resultados = [];\n  let pagina = 1;\n  while (true) {\n    const res = await fetch(`${urlBase}?page=${pagina}`);\n    const datos = await res.json();\n    if (datos.length === 0) break;\n    resultados.push(...datos);\n    pagina++;\n  }\n  return resultados;\n}\n```\n\nCombinamos `push` con spread para acumular resultados.", "exercise": "Crea la función asíncrona `obtenerTodos(urlBase)` que retorne una Promesa que resuelve en un array.", "solution": "async function obtenerTodos(urlBase) {\n  return [];\n}", "tests": ["typeof obtenerTodos === 'function'", "typeof obtenerTodos('test').then === 'function'", "obtenerTodos.length === 1"] },
  { "id": 70, "module": "Asincronía", "title": "Promise combinators avanzados", "theory": "`Promise.any()` resuelve con la primera Promesa exitosa. `Promise.race()` resuelve con la primera en completarse (éxito o error).\n\n```js\nconst lenta = new Promise(r => setTimeout(() => r('lenta'), 2000));\nconst rapida = new Promise(r => setTimeout(() => r('rápida'), 500));\n\nPromise.any([lenta, rapida]).then(console.log); // 'rápida'\nPromise.race([lenta, rapida]).then(console.log); // 'rápida'\n```\n\nLa diferencia clave: `any()` ignora rechazos hasta que una exitosa; `race()` toma la primera sin importar el resultado.", "exercise": "Crea la función `primeraExitosa(promesas)` que retorne el resultado de `Promise.any(promesas)`.", "solution": "function primeraExitosa(promesas) {\n  return Promise.any(promesas);\n}", "tests": ["typeof primeraExitosa === 'function'", "primeraExitosa.length === 1", "typeof primeraExitosa([Promise.resolve(1)]).then === 'function'"] },
  { "id": 71, "module": "Asincronía", "title": "Manejo de errores asincrónicos", "theory": "Los errores asíncronos se manejan con `try/catch` dentro de `async` funciones o con `.catch()` en Promesas.\n\n```js\nasync function ejecutarSeguro(fnAsync) {\n  try {\n    const datos = await fnAsync();\n    return { exito: true, datos, error: null };\n  } catch (error) {\n    return { exito: false, datos: null, error: error.message };\n  }\n}\n```\n\nEste patrón envuelve cualquier función asíncrona en un formato estandarizado sin excepciones no capturadas.", "exercise": "Crea la función asíncrona `ejecutarSeguro(fnAsync)` que retorne una Promesa con `{exito, datos, error}`.", "solution": "async function ejecutarSeguro(fnAsync) {\n  try {\n    const datos = await fnAsync();\n    return { exito: true, datos, error: null };\n  } catch (error) {\n    return { exito: false, datos: null, error: error.message };\n  }\n}", "tests": ["typeof ejecutarSeguro === 'function'", "ejecutarSeguro.length === 1", "typeof ejecutarSeguro(async () => 42).then === 'function'"] },
  { "id": 72, "module": "Optimización y Buenas Prácticas", "title": "Pilas (Stacks)", "theory": "Una **pila (stack)** es una estructura de datos que sigue el principio **LIFO** (Last In, First Out). El último elemento agregado es el primero en salir.\n\n**Operaciones principales:**\n- `push`: agregar un elemento al tope\n- `pop`: eliminar y devolver el elemento del tope\n- `peek`: ver el tope sin eliminarlo\n- `isEmpty`: verificar si está vacía\n\n```js\n// Ejemplo de uso\nconst pila = new Pila();\npila.push(10);\npila.push(20);\nconsole.log(pila.pop()); // 20\nconsole.log(pila.pop()); // 10\n```\n\n**Aplicaciones:** navegación en navegadores, deshacer/rehacer, evaluación de expresiones.", "exercise": "Implementa una clase `Pila` con los métodos `push(elemento)`, `pop()` y `estaVacia()`. La pila debe comportarse en LIFO.", "solution": "class Pila { constructor() { this.elementos = []; } push(e) { this.elementos.push(e); } pop() { return this.elementos.length ? this.elementos.pop() : null; } estaVacia() { return this.elementos.length === 0; } }", "tests": ["const p = new Pila(); p.push(1); p.push(2); p.pop() === 2", "const p = new Pila(); p.estaVacia() === true", "const p = new Pila(); p.push('a'); p.push('b'); p.push('c'); p.pop(); p.pop(); p.pop(); p.estaVacia() === true", "const p = new Pila(); p.push(42); p.push(43); p.push(44); p.pop(); p.pop(); p.pop() === null"] },
  { "id": 73, "module": "Optimización y Buenas Prácticas", "title": "Colas (Queues)", "theory": "Una **cola (queue)** es una estructura de datos que sigue el principio **FIFO** (First In, First Out). El primer elemento agregado es el primero en salir.\n\n**Operaciones principales:**\n- `enqueue` / `encolar`: agregar al final\n- `dequeue` / `desencolar`: eliminar y devolver el primero\n- `front`: ver el primero sin eliminarlo\n- `size`: cantidad de elementos\n\n```js\n// Ejemplo de uso\nconst cola = new Cola();\ncola.encolar('A');\ncola.encolar('B');\nconsole.log(cola.desencolar()); // 'A'\nconsole.log(cola.desencolar()); // 'B'\n```\n\n**Aplicaciones:** colas de impresión, procesamiento de tareas, BFS en grafos.", "exercise": "Implementa una clase `Cola` con los métodos `encolar(elemento)`, `desencolar()` y `tamano()`. La cola debe comportarse en FIFO. Si está vacía, `desencolar()` debe retornar `null`.", "solution": "class Cola { constructor() { this.elementos = []; } encolar(e) { this.elementos.push(e); } desencolar() { return this.elementos.length ? this.elementos.shift() : null; } tamano() { return this.elementos.length; } }", "tests": ["const c = new Cola(); c.encolar(1); c.encolar(2); c.desencolar() === 1", "const c = new Cola(); c.tamano() === 0", "const c = new Cola(); c.encolar('x'); c.encolar('y'); c.encolar('z'); c.desencolar(); c.desencolar(); c.desencolar(); c.tamano() === 0", "const c = new Cola(); c.desencolar() === null"] },
  { "id": 74, "module": "Optimización y Buenas Prácticas", "title": "Sets y Maps", "theory": "**Set** y **Map** son estructuras que garantizan unicidad y asociación clave-valor.\n\n**Set:** colección de valores únicos. No permite duplicados.\n```js\nconst s = new Set([1, 2, 2, 3]);\nconsole.log(s.size); // 3\n```\n\n**Map:** diccionario clave-valor con claves únicas.\n```js\nconst m = new Map();\nm.set('a', 1);\nconsole.log(m.get('a')); // 1\n```\n\nAmbos tienen `O(1)` en insersión y búsqueda promedio.", "exercise": "Crea dos funciones: `elementosUnicos(arr)` que retorne un array con los elementos sin duplicados, y `contarFrecuencias(arr)` que retorne un objeto con la frecuencia de cada elemento.", "solution": "function elementosUnicos(arr) { return [...new Set(arr)]; } function contarFrecuencias(arr) { const m = {}; for (const e of arr) { m[e] = (m[e] || 0) + 1; } return m; }", "tests": ["JSON.stringify(elementosUnicos([1,2,2,3])) === '[1,2,3]'", "JSON.stringify(elementosUnicos(['a','b','a'])) === '[\"a\",\"b\"]'", "JSON.stringify(contarFrecuencias([1,1,2,3,3,3])) === '{\"1\":2,\"2\":1,\"3\":3}'", "contarFrecuencias(['a','b','a'])['a'] === 2"] },
  { "id": 75, "module": "Optimización y Buenas Prácticas", "title": "Búsqueda binaria", "theory": "La **búsqueda binaria** encuentra un elemento en un **array ordenado** en tiempo **O(log n)**, partiendo el espacio de búsqueda a la mitad en cada paso.\n\n```js\nfunction busquedaBinaria(arr, objetivo) {\n  let inicio = 0, fin = arr.length - 1;\n  while (inicio <= fin) {\n    const medio = Math.floor((inicio + fin) / 2);\n    if (arr[medio] === objetivo) return medio;\n    if (arr[medio] < objetivo) inicio = medio + 1;\n    else fin = medio - 1;\n  }\n  return -1;\n}\n```\n\n**Requisito:** el array debe estar ordenado ascendentemente.", "exercise": "Implementa la función `busquedaBinaria(arr, objetivo)` que recibe un array ordenado y un valor a buscar. Retorna el índice si existe, o `-1` si no.", "solution": "function busquedaBinaria(arr, obj) { let lo = 0, hi = arr.length - 1; while (lo <= hi) { const mid = Math.floor((lo + hi) / 2); if (arr[mid] === obj) return mid; if (arr[mid] < obj) lo = mid + 1; else hi = mid - 1; } return -1; }", "tests": ["busquedaBinaria([1,3,5,7,9], 5) === 2", "busquedaBinaria([1,3,5,7,9], 9) === 4", "busquedaBinaria([1,3,5,7,9], 2) === -1", "busquedaBinaria([], 1) === -1"] },
  { "id": 76, "module": "Optimización y Buenas Prácticas", "title": "Recursión", "theory": "La **recursión** ocurre cuando una función se llama a sí misma. Toda función recursiva necesita:\n\n1. **Caso base**: condición que detiene la recursión\n2. **Caso recursivo**: la función se llama con un subproblema más pequeño\n\n```js\n// Factorial\nfunction factorial(n) {\n  if (n <= 1) return 1;\n  return n * factorial(n - 1);\n}\n\n// Fibonacci\nfunction fibonacci(n) {\n  if (n <= 1) return n;\n  return fibonacci(n - 1) + fibonacci(n - 2);\n}\n```\n\n**Advertencia:** sin caso base, la recursión es infinita y causa stack overflow.", "exercise": "Implementa dos funciones recursivas: `factorial(n)` que calcula n! y `fibonacci(n)` que devuelve el n-ésimo número de Fibonacci (empezando en 0).", "solution": "function factorial(n) { if (n <= 1) return 1; return n * factorial(n - 1); } function fibonacci(n) { if (n <= 1) return n; return fibonacci(n - 1) + fibonacci(n - 2); }", "tests": ["factorial(0) === 1", "factorial(5) === 120", "fibonacci(0) === 0", "fibonacci(7) === 13"] },
  { "id": 77, "module": "Optimización y Buenas Prácticas", "title": "Análisis Big O", "theory": "**Big O** mide la eficiencia de un algoritmo según el tamaño de entrada `n`.\n\n| Notación | Nombre | Ejemplo |\n|----------|--------|--------|\n| O(1) | Constante | Acceso a índice de array |\n| O(log n) | Logarítmica | Búsqueda binaria |\n| O(n) | Lineal | Recorrer un array |\n| O(n²) | Cuadrática | Bucles anidados |\n\n```js\n// O(n) - lineal\nfunction sumar(arr) {\n  let total = 0;\n  for (let i = 0; i < arr.length; i++) total += arr[i];\n  return total;\n}\n```\n\nElegir el algoritmo adecuado puede marcar la diferencia entre milisegundos y horas.", "exercise": "Implementa la función `analizarComplejidad(fn)` que recibe una función y retorna un string descriptivo según su complejidad: 'O(1): Constante', 'O(n): Lineal', 'O(n²): Cuadrática', 'O(log n): Logarítmica'.", "solution": "function analizarComplejidad(fn) { const fnStr = fn.toString(); if (/forEach|map|filter|for\\(|while\\(/.test(fnStr) && (fnStr.match(/for\\(|forEach|map|while\\(/g) || []).length >= 2) return 'O(n²): Cuadrática'; if (/forEach|map|filter|for\\(|while\\(/.test(fnStr)) return 'O(n): Lineal'; if (/log|binary|mitad/.test(fnStr)) return 'O(log n): Logarítmica'; return 'O(1): Constante'; }", "tests": ["analizarComplejidad(function simple() { return 42; }) === 'O(1): Constante'", "analizarComplejidad(function lineal(arr) { for(let x of arr) console.log(x); }) === 'O(n): Lineal'", "analizarComplejidad(function cuadratica(m) { for(let i of m) for(let j of i) console.log(j); }) === 'O(n²): Cuadrática'", "typeof analizarComplejidad === 'function'"] },
  { "id": 78, "module": "Proyectos Finales", "title": "Juego Memory", "theory": "El **juego Memory** consiste en encontrar pares de cartas iguales. El tablero tiene `n × 2` cartas donde cada número aparece exactamente dos veces.\n\n**Lógica del juego:**\n1. Generar un tablero con pares mezclados\n2. El jugador destapa dos cartas\n3. Si son iguales, el par se queda descubierto\n4. Si no, se vuelven a ocultar\n\n```js\nfunction crearTablero(n) {\n  const valores = [];\n  for (let i = 1; i <= n; i++) valores.push(i, i);\n  return valores.sort(() => Math.random() - 0.5);\n}\n```\n\nEste proyecto ejercita manipulación de arrays, eventos y estado de la aplicación.", "exercise": "Implementa `crearTablero(n)` que retorna un array de 2n elementos con pares del 1 al n mezclados, y `verificarPar(id1, id2)` que retorna `true` si los valores en esas posiciones coinciden (el tablero se almacena en una variable global `tablero`).", "solution": "const tablero = []; function crearTablero(n) { const vals = []; for (let i = 1; i <= n; i++) vals.push(i, i); tablero.length = 0; tablero.push(...vals.sort(() => Math.random() - 0.5)); return tablero; } function verificarPar(i, j) { return tablero[i] === tablero[j]; }", "tests": ["typeof crearTablero === 'function'", "typeof verificarPar === 'function'", "crearTablero(4).length === 8", "(() => { const t = crearTablero(3); return t.sort((a,b)=>a-b).join(',') === '1,1,2,2,3,3'; })()"] },
  { "id": 79, "module": "Proyectos Finales", "title": "Router SPA", "theory": "Un **Router SPA** permite navegar entre vistas sin recargar la página, cambiando el contenido dinámicamente.\n\n```js\nclass Router {\n  constructor() {\n    this.rutas = {};\n    this.rutaActual = null;\n  }\n  addRuta(path, componente) {\n    this.rutas[path] = componente;\n  }\n  navegar(path) {\n    this.rutaActual = this.rutas[path] || null;\n    return this.rutaActual;\n  }\n}\n```\n\n**Conceptos clave:** manipulación del DOM, eventos de clic, cambio de estado sin recarga.", "exercise": "Implementa una clase `Router` con los métodos `addRuta(path, componente)` para registrar rutas y `navegar(path)` que actualiza `currentRoute` con el componente asociado (o `null` si no existe).", "solution": "class Router { constructor() { this.rutas = {}; this.currentRoute = null; } addRuta(p, c) { this.rutas[p] = c; } navegar(p) { this.currentRoute = this.rutas[p] || null; return this.currentRoute; } }", "tests": ["const r = new Router(); r.addRuta('/', 'home'); r.navegar('/'); r.currentRoute === 'home'", "const r = new Router(); r.addRuta('/home','Home'); r.addRuta('/about','About'); r.navegar('/about'); r.currentRoute === 'About'", "const r = new Router(); r.navegar('/no-existe'); r.currentRoute === null", "const r = new Router(); r.addRuta('/x','X'); r.navegar('/x'); r.navegar('/y'); r.currentRoute === null"] },
  { "id": 80, "module": "Proyectos Finales", "title": "Dashboard con datos", "theory": "Un **dashboard** muestra datos transformados de una fuente. Las operaciones típicas incluyen:\n\n- **Cargar**: obtener datos (simulados)\n- **Filtrar**: seleccionar subconjuntos\n- **Agregar**: calcular métricas (promedios, totales)\n\n```js\nconst usuarios = [\n  { nombre: 'Ana', edad: 25, activo: true },\n  { nombre: 'Luis', edad: 32, activo: false },\n];\n\nfunction promedioEdad(lista) {\n  const total = lista.reduce((s, u) => s + u.edad, 0);\n  return total / lista.length;\n}\n```\n\nDomina transformaciones de datos con arrays y objetos.", "exercise": "Implementa tres funciones: `cargarUsuarios()` que retorna un array con 5 usuarios (nombre, edad, activo), `filtrarUsuarios(usuarios, activo)` que filtra por estado, y `promedioEdad(usuarios)` que calcula el promedio de edad.", "solution": "function cargarUsuarios() { return [{nombre:'Ana',edad:25,activo:true},{nombre:'Luis',edad:32,activo:false},{nombre:'Sofía',edad:28,activo:true},{nombre:'Carlos',edad:40,activo:false},{nombre:'Elena',edad:22,activo:true}]; } function filtrarUsuarios(u,a) { return u.filter(x => x.activo === a); } function promedioEdad(u) { return u.reduce((s,x)=>s+x.edad,0)/u.length; }", "tests": ["cargarUsuarios().length === 5", "filtrarUsuarios(cargarUsuarios(), true).length === 3", "typeof promedioEdad(cargarUsuarios()) === 'number'", "filtrarUsuarios(cargarUsuarios(), false).length === 2"] },
  { "id": 81, "module": "Proyectos Finales", "title": "Carrito de compra persistente", "theory": "Un **carrito de compras** con persistencia permite mantener los items incluso al cerrar el navegador usando **localStorage**.\n\n```js\nclass Carrito {\n  constructor() {\n    this.items = [];\n    this.cargar();\n  }\n  agregar(producto) {\n    this.items.push(producto);\n    this.guardar();\n  }\n  quitar(id) {\n    this.items = this.items.filter(i => i.id !== id);\n    this.guardar();\n  }\n  get total() {\n    return this.items.reduce((s, i) => s + i.precio, 0);\n  }\n  guardar() {\n    localStorage.setItem('carrito', JSON.stringify(this.items));\n  }\n  cargar() {\n    const data = localStorage.getItem('carrito');\n    this.items = data ? JSON.parse(data) : [];\n  }\n}\n```\n\nCombina clases, arrays y Web Storage API.", "exercise": "Implementa la clase `Carrito` con `agregar(producto)`, `quitar(id)`, `get total()`, `guardar()` y `cargar()`. Usa un array interno `items`. Los productos tienen `{id, nombre, precio}`.", "solution": "class Carrito { constructor() { this.items = []; } agregar(p) { this.items.push(p); this.guardar(); } quitar(id) { this.items = this.items.filter(i => i.id !== id); this.guardar(); } get total() { return this.items.reduce((s,i) => s + i.precio, 0); } guardar() { localStorage.setItem('carrito', JSON.stringify(this.items)); } cargar() { const d = localStorage.getItem('carrito'); this.items = d ? JSON.parse(d) : []; } }", "tests": ["const c = new Carrito(); c.agregar({id:1,nombre:'A',precio:10}); c.items.length === 1", "const c = new Carrito(); c.agregar({id:1,nombre:'A',precio:10}); c.agregar({id:2,nombre:'B',precio:20}); c.total === 30", "const c = new Carrito(); c.agregar({id:1,nombre:'A',precio:10}); c.agregar({id:2,nombre:'B',precio:20}); c.quitar(1); c.items.length === 1", "typeof Carrito.prototype.guardar === 'function'"] }
];
export default LESSONS;
